            "code": "  private operateTaskBatchHandle(event: EventInterface, type: OperateTaskType): void {\n    const tableCpm = this.getContentCom<DppTableComponent>(event);\n    const rowDataNodes = tableCpm.getCheckedNodeList();\n    let datas = rowDataNodes.map(i => {\n      return {\n        GUID$: i.origin['GUID$'],\n        CLASSGUID$: i.origin['CLASSGUID$'],\n        CLASSNAME$: i.origin['CLASSNAME$']\n      };\n    });\n    datas = datas.filter(item => {\n      return item['CLASSNAME$'] !== 'Project';\n    });\n    if (!datas) return;\n    // const rowDataNodes = tableCpm.getCheckedNodes();\n    const ganttCpm = this.getRootPageService(event).getComFnMapByName<GanttComponent>(\n      CommandConstant.ProjectWbsCommand\n    )!;\n    this.setLoading(event, true);\n    this.projectManageService.batchOperateTask(datas, type).subscribe({\n      next: res => {\n        if (res.success) {\n          const batchParams: BatchParams = {\n            tableCpm,\n            ganttCpm,\n            tranPipe: this.tranPipe,\n            batchDatas: res.data!,\n            message: this.dppMessageService,\n            type,\n            as: this.as,\n            bs: this.getExeCom<DppButtonComponent>(event),\n            projectService: this.projectManageService\n          };\n          GanttEventUtil.batchHandle(batchParams);\n        }\n        this.setLoading(event, false);\n      },\n      error: () => {\n        this.setLoading(event, false);\n      }\n    });\n  }"
