            "code": "  sysTemplateTaskExportAction(event: EventInterface): void {\n    const project = this.getRootPageService(event).getInstanceData();\n    // const bs = this.getExeCom(event) as DppButtonComponent;\n    const param = {\n      CLASSNAME$: project?.['CLASSNAME$'],\n      GUID$: project?.['GUID$']\n    };\n    this.setLoading(event, true);\n    this.projectManageService.exportProject(param).subscribe({\n      next: res => {\n        if (res.success && res.data) {\n          const fileName = project?.['FULLNAME$'];\n          const url = window.URL.createObjectURL(res.data);\n          const link = document.createElement('a');\n          link.target = '_blank';\n          link.download = `${fileName}.xml`;\n          link.href = url;\n          link.click();\n          window.URL.revokeObjectURL(url);\n          this.dppMessageService.success('systemSetting.organization.groupManagment.title.exportSuccess');\n        }\n        this.setLoading(event, false);\n      },\n      error: () => {\n        this.setLoading(event, false);\n      }\n    });\n  }"
