            "code": "  sysTaskTemplateBatchCopyAction(event: EventInterface): void {\n    const tableCom = this.getContentCom<DppTableComponent>(event);\n    const tableSelectDatas = tableCom.getCheckedNodeList();\n    const copyObject: clipBoardValueType[] = [];\n    tableSelectDatas.forEach(data => {\n      const temp = {\n        GUID: data.origin['GUID$'],\n        CLASSGUID: data.origin['CLASSGUID$'],\n        CLASSNAME: data.origin['CLASSNAME$'],\n        FULLNAME: data.origin['FULLNAME$']\n      };\n      temp['type'] = TaskTemplateOption.className;\n      temp['origin'] = data.origin;\n      copyObject.push(temp);\n    });\n    this.clipBoardService.addValueByType(clipBoardTypeEnum.OBJECT_TYPE, copyObject);\n  }"
