            "name": "sysTaskTemplateCopyAction",
            "lines": 12,
            "event_type": "(event: EventInterface)",
            "note": "复制",
            "code": "  sysTaskTemplateCopyAction(event: EventInterface): void {\n    const data: IFoundaton = this.getRowData(event);\n    const temp = {\n      GUID: data['END2#GUID$'] ? data['END2#GUID$'] : data['GUID$'],\n      CLASSGUID: data['END2#CLASSGUID$'] ? data['END2#CLASSGUID$'] : data['CLASSGUID$'],\n      CLASSNAME: data['END2#CLASSNAME$'] ? data['END2#CLASSNAME$'] : data['CLASSNAME$'],\n      FULLNAME: data['END2#FULLNAME$'] ? data['END2#FULLNAME$'] : data['FULLNAME$']\n    };\n    temp['type'] = TaskTemplateOption.className;\n    temp['origin'] = data;\n    this.clipBoardService.addValueByType(clipBoardTypeEnum.OBJECT_TYPE, new Array<clipBoardValueType>(temp));\n  }"
