            "note": "转为子项目",
            "code": "  sysTaskRotorItemAciton(event: EventInterface): void {\n    const bs = event.exeComFn() as DppButtonComponent;\n    const tableCpm = this.getContentCom<DppTableComponent>(event);\n    const rowData = this.getRowData(event) as ITask;\n    const rowDataNode = this.getNode(event) as RowNode;\n    // tableCpm.getFlatRootNodes\n    const render: IRenderParameterNew<IUiModel> = {\n      name: 'sysTranProjectPage',\n      mParams: {\n        mode: ModeTypeEnum.EDIT\n      },\n      data: {\n        ID$: `${rowData['OWNERPROJECT$ID']}-${rowData['WBSNUMBER']}`\n      },\n      dParams: {},\n      innerSend: {\n        drawerSelf: () => modal,\n        triggerInstance: () => tableCpm\n      }\n    };\n    render.data!['EXECUTOR'] = rowData['EXECUTOR'];\n    render.data!['EXECUTOR$ID'] = rowData['EXECUTOR$ID'];\n    render.data!['EXECUTOR$NAME'] = rowData['EXECUTOR$NAME'];\n    this.tranRowDataNode = rowDataNode;\n\n    const param: ConvertProParam = {\n      PROJECTCLASSNAME: rowData.OWNERPROJECT$CLASSNAME,\n      PROJECTGUID: rowData.OWNERPROJECT,\n      TASKCLASSNAME: rowData.CLASSNAME$,\n      TASKGUID: rowData.GUID$\n    };\n    Object.assign(render.data!, param);\n\n    // const rigs = tableCpm.dppRender.dParams!['RIGLIST'] as Array<DppOption<IRig>>;\n    // if (rigs) {\n    //   render.data!['RIGLIST'] = rigs.map(i => i.origin!.GUID || i.origin!.GUID$);\n    // }\n    const modal = this.as.openDrawer(\n      {\n        title: bs.getUiModel().label,\n        uiType: 'page',\n        isInteractive: true,\n        drawerSelf: () => modal,\n        triggerInstance: () => tableCpm,\n        mask: true,\n        maskClosable: true\n      },\n      {\n        dppRender: render\n      }\n    ) as DppNzDrawerRef;\n  }"
