            "code": "  sysTaskBatchSetExeRoleAciton(event: EventInterface): void {\n    const bs = event.exeComFn() as DppButtonComponent;\n    const tableCpm = this.getContentCom<DppTableComponent>(event);\n    const rowDataNodes = tableCpm.getCheckedNodeList();\n    const rowData = rowDataNodes[0].origin as unknown as ITask;\n\n    const render: IRenderParameterNew<IUiModel> = {\n      name: bs.getUiModel().action?.name,\n      mParams: {\n        mode: ModeTypeEnum.EDIT,\n        isObject: false\n      },\n      data: {},\n      dParams: {\n        projectGuid: rowData.OWNERPROJECT\n      }\n    };\n\n    const model = CommonEventUtil.buildDefaultModal<NotifySelectiveComponent>(\n      event,\n      (button, cpm) => {\n        button.loading = true;\n        this.setLoading(event, true);\n\n        if (cpm.displayAreaData.length === 0) {\n          button.loading = false;\n          this.setLoading(event, false);\n          this.dppMessageService.warning('请选择');\n          return;\n        }\n\n        const ganttCpm = this.getRootPageService(event).getComFnMapByName<GanttComponent>(\n          CommandConstant.ProjectWbsCommand\n        )!;\n\n        const datas: Array<{ GUID$: string; CLASSGUID$: string; CLASSNAME$: string }> = [];\n        rowDataNodes.forEach(item => {\n          datas.push({\n            GUID$: item.origin['GUID$'],\n            CLASSGUID$: item.origin['CLASSGUID$'],\n            CLASSNAME$: item.origin['CLASSNAME$']\n          });\n        });\n        this.setLoading(event, true);\n        this.projectManageService.batchSetExeRole(datas, cpm.displayAreaData[0]['guid']!).subscribe({\n          next: res => {\n            button.loading = false;\n            this.setLoading(event, false);\n            if (!res.success) {\n              return;\n            }\n            const batchParams: BatchParams = {\n              tableCpm,\n              ganttCpm,\n              tranPipe: this.tranPipe,\n              batchDatas: res.data!,\n              message: this.dppMessageService,\n              as: this.as,\n              bs: this.getExeCom<DppButtonComponent>(event),\n              type: 'complete',\n              projectService: this.projectManageService\n            };\n            GanttEventUtil.batchHandle(batchParams);\n            model.close();\n          },\n          error: () => {\n            button.loading = false;\n            this.setLoading(event, false);\n          }\n        });\n      },\n      this.dppMessageService,\n      {\n        TABS: ['team'],\n        dppRender: {\n          dParams: {\n            type: 'team',\n            projectGuid: rowData.OWNERPROJECT,\n            disabledConfig: {\n              disabledType: 'USER',\n              contentTab: 'team'\n            },\n            isMultiple: false\n          }\n        }\n      },\n      false,\n      undefined,\n      NotifySelectiveComponent\n    );\n  }"
