            "code": "  sysProducChangeAction(event: EventInterface): void {\n    const rootPage = this.getRootPageService(event);\n    const instanceData = rootPage.getInstanceData();\n    const params: IFormRender = {\n      name: 'sysProjectChangeForm',\n      mParams: {\n        mode: ModeTypeEnum.EDIT,\n        isObject: false\n      },\n      data: {}\n    };\n    const modal = this.as.openModal(\n      {\n        title: 'project.title.projectChangeReason',\n        width: '580px',\n        content: DppFormComponent,\n        bodyStyle: { height: '220px' },\n        footer: [\n          {\n            label: 'common.button.cancel',\n            type: 'default',\n            onClick: (): void => {\n              modal.close();\n            }\n          },\n          {\n            label: 'common.button.confirm',\n            type: 'primary',\n            onClick: (formCpn: DppFormComponent) => {\n              const isValid = formCpn.onSubmit();\n              if (isValid) {\n                formCpn.setLoading(true);\n                const formData = formCpn.getFormData<IBaseData>();\n                const params = {\n                  ChangeObject$CLASS: instanceData['CLASSGUID$'],\n                  ChangeObjeCt$MASTER: instanceData['MASTERFK$'],\n                  ChangeObject: instanceData['GUID$'],\n                  CHANGETYPE: formData['CHANGETYPE'],\n                  SOLUTION: formData['SOLUTION'],\n                  DESCRIPTION: formData['DESCRIPTION'],\n                  BGDJ: formData['BGDJ']\n                };\n                this.projectManageService.createChange(params).subscribe({\n                  next: res => {\n                    if (res.success) {\n                      this.dppMessageService.success('common.operation.operationSuccess');\n                      formCpn.setLoading(false);\n                      modal.close();\n                      this.refreshInstance(event);\n                    }\n                  },\n                  error: error => {\n                    formCpn.setLoading(false);\n                  }\n                });\n              }\n            }\n          }\n        ]\n      },\n      { dppRender: params }\n    );\n  }"
