            "code": "  sysProductManageSaveAction(event: EventInterface): void {\n    // this.dppMessageService.info('项目保存');\n    // const com = this.getContentCom<projectManageChartComponent | projectTemplateChartComponent>(event);\n    // const form = com.projectForm;\n    const form = this.getContentCom<DppFormComponent>(event);\n    const allData = form.getFormData<IFoundaton>();\n    const data = form.getFormChanceData<IFoundaton>();\n    const pageService = this.getRootPageService(event);\n    // const rootPage = this.getRootPageService(event);\n    // const instanceData = rootPage.getInstanceData();\n    const params = {\n      GUID$: allData['GUID$'],\n      CLASSNAME$: allData['CLASSNAME$'],\n      CLASSGUID$: allData['CLASSGUID$'],\n      CLASSIFICATION$: allData['CLASSIFICATION$'],\n      ...data\n    };\n    this.projectManageService.saveProject(params).subscribe(res => {\n      if (res.success) {\n        this.dppMessageService.success('common.operation.operationSuccess');\n        pageService.refreshInstanceData({ isRefreshSelf: true });\n      }\n    });\n  }"
