            "code": "  sysProjectPasteTeamAction(event: EventInterface): void {\n    const tableCom = this.getContentCom<DppTableComponent>(event);\n    const pasteProject = tableCom.dppRender.dParams;\n    const copyProject = this.authUserService.getPpmTeamSource() as { guid: string };\n\n    if (!copyProject) {\n      this.dppMessageService.warning('productdesign.operation.noResourceCanPaste');\n      return;\n    }\n    if (copyProject.guid === pasteProject?.guid) {\n      this.dppMessageService.warning('common.operation.pasteSelf');\n      return;\n    }\n    this.projectManageService\n      .pasteProjectTeam({\n        copyProject: {\n          ...copyProject\n        },\n        pasteProject: {\n          ...pasteProject\n        }\n      })\n      .subscribe({\n        next: res => {\n          if (res.success) {\n            this.dppMessageService.success('common.operation.operationSuccess');\n            tableCom.refreshData();\n          }\n        },\n        error: res => {\n          let errorMes = res?.error?.errorMessage;\n          if (!errorMes) {\n            errorMes = res?.message;\n          }\n          this.dppMessageService.error(errorMes);\n        }\n      });\n  }"
