            "code": "  sysTeamResourceWorkloadAction(event: EventInterface): void {\n    const table = this.getContentCom(event) as unknown as DppTableComponent;\n    const renderData = table.dppRender.data as { CLASSGUID$: string; GUID$: string };\n    const rowData = this.getRowData(event) as {\n      'END2#USERGUID': string;\n      'END2#ROLEGUID': string;\n      GUID$: string;\n      'PROJECT#PLANSTARTTIME': string;\n    };\n\n    const project = this.getRootPageService(event).getInstanceData();\n    const stratTime = new CandyDate(project['PLANSTARTTIME']);\n\n    const render = {\n      dParams: {\n        // roles: [rowData['PROJECTROLE']],\n        users: [rowData['END2#USERGUID']],\n        startTime: this.datePipe.transform(stratTime.nativeDate, 'yyyy/MM/dd'),\n        endTime: this.datePipe.transform(stratTime.addMonths(1).nativeDate, 'yyyy/MM/dd')\n      },\n      mParams: {\n        dataSource:\n          '/workload/listUserWorkingChildren?PROJECT=$PROJECTGUID&roles=$roles&users=$USERGUID&startTime=$STARTTIME&endTime=$ENDTIME',\n        rootSource: '/workload/listUserWorkingRoots?roles=$roles&users=$users&startTime=$startTime&endTime=$endTime',\n        modeType: 'workload',\n        tableName: 'sysWorkloadTable'\n      }\n    };\n    this.as.openModal(\n      {\n        title: 'project.TeamResources.ResourceLoadQuery',\n        full: true,\n        openModalCloseDrawer: false,\n        content: GanttComponent,\n        footer: 'noFooter'\n      },\n      {\n        dppRender: render\n      }\n    );\n  }"
