            "event_type": "(event: EventInterface)",
            "note": "新建预警",
            "code": "  sysProductWarningAddAction(event: EventInterface): void {\n    // eslint-disable-next-line @typescript-eslint/no-this-alias\n    const that = this;\n    const page = this.getRootPageService(event);\n    const instanceData = page.getInstanceData();\n    const table = this.getContentCom<DppTableComponent>(event);\n    const formParams: IFormRender = {\n      mParams: {\n        mode: ModeTypeEnum.EDIT,\n        isObject: false\n      },\n      dParams: {\n        className: instanceData['CLASSNAME$'],\n        guid: instanceData['GUID$']\n      },\n      name: 'sysProductWarningAddForm'\n    };\n    const modal = this.as.openModal(\n      {\n        title: 'project.title.newWarning',\n        width: '700px',\n        height: 'auto',\n        closable: true,\n        bodyStyle: {\n          minHeight: '100px'\n        },\n        content: DppFormComponent,\n        footer: [\n          {\n            label: 'common.button.cancel',\n            type: 'default',\n            onClick: () => {\n              modal.close();\n            }\n          },\n          {\n            label: 'common.button.confirm',\n            type: 'primary',\n            onClick(formCpn: any) {\n              const isValid = formCpn.onSubmit();\n              const formData = formCpn.getNotTranFormData() as DppSafeAny;\n              const formTable = formCpn.service.getFieldCpmByKey('APPLYTOTASKLIST');\n              const treeNodes = formTable?.table?.getTreeNodes();\n              let originsApplyToTaskList: any = [];\n              if (treeNodes) {\n                treeNodes.forEach((item: any) => {\n                  originsApplyToTaskList.push({\n                    guid: item.origin['GUID$'],\n                    classGuid: item.origin['CLASSGUID$']\n                  });\n                });\n              }\n\n              let originsNoticeMemberList: any = [];\n\n              if (formData['NOTICEMEMBERLIST']) {\n                formData['NOTICEMEMBERLIST'].forEach((obj: any) => {\n                  originsNoticeMemberList.push({\n                    NOTIFIERTYPE: obj.origin['type'],\n                    NOTIFIERGUID: obj.origin['key'],\n                    sorted: obj.sorted\n                  });\n                });\n              }\n\n              const saveData = {\n                PROJECTGUID: instanceData['GUID$'],\n                EVENTTYPE: formData['EVENTTYPE'].value,\n                INTERVALUE: `${formData['INTERVALUE']}`,\n                REMARKS: formData['REMARKS'],\n                ISENABLE: formData['ISENABLE'] ? formData['ISENABLE'] : 'N',\n                RELATEDOBJECTTYPE: formData['RELATEDOBJECTTYPE']?.value,\n                noticeMemberList: originsNoticeMemberList,\n                applyToTaskList: originsApplyToTaskList\n              };\n              if (isValid) {\n                this.loading = true;\n                formCpn.setLoading(true);\n                that.projectManageService.saveWarningRule(saveData).subscribe({\n                  next: res => {\n                    if (res.success) {\n                      // that.contentComCallback(event, {\n                      //   operate: EventCallbacksActionName.REFRESH\n                      // });\n                      modal.close();\n                      this.loading = true;\n                      formCpn.setLoading(true);\n                      table.refreshData();\n                    }\n                  },\n                  error: err => {\n                    this.loading = false;\n                    formCpn.setLoading(false);\n                  }\n                });\n              }\n            }\n          }\n        ]\n      },\n      {\n        dppRender: formParams\n      }\n    );\n  }"
