            "note": "指定任务新增",
            "code": "  sysWarningAssignedTaskAddAction(event: EventInterface): void {\n    const tableCon = this.getContentCom(event) as unknown as DppTableComponent;\n    const tri = tableCon?.dppRender?.innerSend?.triggerInstance?.();\n    const selectedTreeNodes = tableCon.getFlatRootNodes();\n\n    const dppRender = {\n      name: 'sysRelevanceWbsTable',\n      mParams: {\n        mode: 'edit',\n        ui: 'table',\n        rootSource: `/task/listRoot?GUID$=${tri.dppRender.dParams.guid}&CLASSNAME$=${tri.dppRender.dParams.className}`,\n        type: 'builtin',\n        dataSource: `/task/listSubTask?GUID$=$GUID$&CLASSNAME$=$CLASSNAME$&level=1`,\n        height: '500px',\n        checkStrictly: true\n      },\n      dParams: {\n        isHide: true\n      }\n    };\n    const modal = this.as.openModal(\n      {\n        title: 'project.warningTable.AssociatedTasks',\n        width: '800px',\n        closable: true,\n        content: DppTableComponent,\n        footer: [\n          {\n            label: 'common.button.cancel',\n            type: 'default',\n            onClick: formCpn => {\n              modal.close();\n            }\n          },\n          {\n            label: 'common.button.confirm',\n            type: 'primary',\n            onClick: (table: DppTableComponent) => {\n              const nodes = table.getCheckedNodes();\n              //遍历nodes，删掉其中level===0的项即删除根节点\n              for (let i = 0; i < nodes.length; i++) {\n                if (nodes[i].level === 0) {\n                  nodes.splice(i, 1);\n                  i--;\n                }\n              }\n              const differentNodes = nodes.filter(i => {\n                return !selectedTreeNodes.some(j => j.origin['GUID$'] === i.origin['GUID$']);\n              });\n              const sendNodes = differentNodes.map(item => ({\n                ...item.origin\n              }));\n              sendNodes.forEach(i => {\n                tableCon.addData(i);\n              });\n              modal.close();\n            }\n          }\n        ]\n      },\n      {\n        dppRender\n      }\n    );\n\n    // 选中已选择的节点，没有规划，复杂，暂不做\n    // modal.afterOpen.subscribe(() => {\n    //   const insideContent = (modal as DppNzModalRef).componentInstance as DppTableComponent;\n    //   insideContent.afterQueryData.subscribe(res => {\n    //     if (res) {\n    //       const targetNodes = getTargetTableNodesByNodes(selectedTreeNodes, insideContent);\n    //       if (targetNodes.length > 0) {\n    //         insideContent.setNodeChecked(targetNodes, true);\n    //       }\n    //     }\n    //   });\n    // });\n\n    // function getTargetTableNodesByNodes(nodes: RowNode[], targetTable: DppTableComponent): RowNode[] {\n    //   if (!nodes || nodes.length === 0) {\n    //     return [];\n    //   }\n    //   let result: RowNode[] = [];\n    //   // 拿到指定table的所有nodes\n    //   const targetTableNodes = targetTable.getFlatRootNodes();\n    //   const nodeKeys = nodes.map(node => node.key);\n\n    //   result = targetTableNodes.filter(node => nodeKeys.includes(node.key));\n    //   return result;\n    // }\n  }"
