            "code": "  sysTaskResourceWorkloadAction(event: EventInterface): void {\n    const table = this.getContentCom(event) as unknown as DppTableComponent;\n    const tableData = table.getTreeNodes();\n    const renderData = table.dppRender.data as { OWNERPROJECT$CLASS: string; OWNERPROJECT: string; GUID$: string };\n    const rowData = this.getRowData(event) as {\n      USERGUID: string;\n      PROJECTROLE: string;\n      GUID$: string;\n      RESOURCERATE: number;\n      'PROJECT#PLANFINISHTIME': string;\n      'PROJECT#PLANSTARTTIME': string;\n    };\n\n    // if (rowData['RESOURCERATE'] === 0) {\n    //   // this.dppMessageService.error(`当前执行人占比为0，不能查看资源负荷！`);\n    //   this.dppMessageService.error('project.message.error.proportionCannotBeZero');\n    //   return;\n    // }\n\n    const ratioTotal = tableData\n      .map(item => {\n        return Number(item.origin['RESOURCERATE']);\n      })\n      .reduce((item, current) => item + current, 0);\n    if (ratioTotal !== 100) {\n      // this.dppMessageService.error(`执行人占比总和为${ratioTotal}%，不等于100%，请先设置！`);\n      const msg = this.tranPipe.transform('project.message.error.totalExecutorProportion', {\n        param: ratioTotal\n      });\n      this.dppMessageService.error(msg);\n      return;\n    }\n\n    const startTime = new CandyDate(rowData['PROJECT#PLANSTARTTIME']);\n\n    const render = {\n      dParams: {\n        // PROJECT$CLASSGUID: renderData['OWNERPROJECT$CLASS'],\n        // PROJECT: renderData['OWNERPROJECT'],\n\n        // roles: [rowData['PROJECTROLE']],\n        users: [rowData['USERGUID']],\n        startTime: this.datePipe.transform(startTime.nativeDate, 'yyyy/MM/dd'),\n        endTime: this.datePipe.transform(startTime.addMonths(1).nativeDate, 'yyyy/MM/dd')\n      },\n      mParams: {\n        dataSource:\n          '/workload/listUserWorkingChildren?PROJECT=$PROJECTGUID&roles=$roles&users=$USERGUID&startTime=$STARTTIME&endTime=$ENDTIME',\n        rootSource: '/workload/listUserWorkingRoots?roles=$roles&users=$users&startTime=$startTime&endTime=$endTime',\n        modeType: 'workload',\n        tableName: 'sysWorkloadTable'\n      }\n    };\n    this.as.openModal(\n      {\n        title: 'project.TeamResources.ResourceLoadQuery',\n        full: true,\n        openModalCloseDrawer: false,\n        content: GanttComponent,\n        footer: 'noFooter'\n      },\n      {\n        dppRender: render\n      }\n    );\n  }"
