            "code": "    // 新增BOM模板(废弃)\n    tempSysBomNewTemplateAction(event: EventInterface): void {\n        const formParams: IFormRender = {\n            name: FormConfigModelEnum.NEWBOMFORM,\n            mParams: {\n                mode: ModeTypeEnum.EDIT,\n                isObject: false\n            }\n        }\n        const modal = this.as.openModal(\n            {\n                title: 'systemSetting.bomTemplate.commonTitle.newTemplate',\n                width: '600px',\n                height: '600px',\n                closable: true,\n                content: DppFormComponent,\n                footer: [\n                    {\n                        label: 'common.button.cancel',\n                        type: 'default',\n                        onClick: formCpn => {\n                            formCpn.reset()\n                            modal.close()\n                        }\n                    },\n                    {\n                        label: 'common.button.confirm',\n                        type: 'primary',\n                        onClick: formCpn => {\n                            const isValid = formCpn.onSubmit()\n                            const formData = formCpn.getNotTranFormData()\n                            formData.STRUCTURECLASSGUID = formData.STRUCTURECLASSNAME?.guid\n                            delete formData.STRUCTURECLASSNAME\n                            formData.VIEWCLASSGUID = formData.VIEWCLASSNAME?.guid\n                            delete formData.VIEWCLASSNAME\n                            if (isValid) {\n                                formCpn.setLoading(true)\n                                this.bomManagement.saveBOMTemplate(formData).subscribe({\n                                    next: res => {\n                                        formCpn.setLoading(false)\n                                        if (res.success) {\n                                            this.dppMessageService.success('common.operation.newSuccess')\n                                            this.contentComCallback(event, {\n                                                operate: EventCallbacksActionName.UPDATE,\n                                                params: { isKeepPage: true, ...res.data }\n                                            })\n                                        }\n                                    },\n                                    error: err => {\n                                        formCpn.setLoading(false)\n                                    }\n                                })\n                                modal.close()\n                            }\n                        }\n                    }\n                ]\n            },\n            {\n                dppRender: formParams\n            }\n        )\n    }",
