            "note": "// 搜索bom模板",
            "code": "    // 搜索bom模板\n    tempSysBomTemplateSearchAction(event: EventInterface): void {\n        const button: DppButtonComponent = this.getExeCom<DppButtonComponent>(event)\n        // eslint-disable-next-line @typescript-eslint/no-explicit-any\n        const inputvalue: string = button.value\n        const searchCondition = new QueryCondition(DppQueryConditionOperator.OR)\n\n        if (!inputvalue) {\n            searchCondition['items']?.push({\n                name: 'TEMPLATENAME',\n                operator: 'Like',\n                values: ['']\n            })\n            this.contentComCallback(event, {\n                operate: EventCallbacksActionName.SEARCH,\n                dwQueryCondition: searchCondition\n            })\n            return\n        }\n        searchCondition.addCondition(new QueryConditionInfo('TEMPLATENAME', [inputvalue], DppQueryConditionOperator.LIKE))\n        this.contentComCallback(event, {\n            operate: EventCallbacksActionName.SEARCH,\n            dwQueryCondition: searchCondition,\n            buttonResetCallback: button.buttonResetCallback\n        })\n    }"
