            "note": "/** 设置BOM为缺省值\n* @param event EventInterface\n*/",
            "code": "    /** 设置BOM为缺省值\n     * @param event EventInterface\n     */\n    sysBomSetDefaultAction(event: EventInterface): void {\n        const rowData = this.getRowData(event)\n        const table = this.getContentCom<DppTableComponent>(event)\n        // 遍历找到原来的默认缺省值\n        // const datas = this.getData(event) as IBaseData[];\n        // const defaultData = datas.find(item => item['ISDEFAULT'] === 'Y') || {};\n        const params = {\n            templateName: rowData['TEMPLATENAME']\n        }\n        this.bomManagement.setDefaultBOMTemplate(params).subscribe({\n            next: res => {\n                table.refreshData()\n                this.dppMessageService.success('common.operation.operationSuccess')\n            },\n            error: () => {\n                this.dppMessageService.error('common.operation.operationFail')\n            }\n        })\n    }"
