            "code": "  // 分类管理规则table和码段table 点击交互\n  SysClassRulesClick(event: EventInterface): void {\n    const bottom_table = this.getContentCom<DppTableComponent>(event);\n    const rowData = this.getRowData(event);\n    bottom_table.dppRender.dParams!['classficationFeatureItemguid'] = rowData['guid'];\n    bottom_table.dppRender.dParams!['ISINHERIT'] = rowData['ISINHERIT'] || '';\n    // 那table的toolbar实例 更新toolbar入参，改变按钮状态\n    console.log(bottom_table.modelManager.initParams);\n    console.log(bottom_table.dppRender);\n  }"
