            "event_type": "event: EventInterface, type: boolean",
            "code": "  CodeSegmentMoveupAction(event: EventInterface, type: boolean): void {\n    const table = this.getContentCom(event) as DppTableComponent;\n    const rowData = this.getRowData(event);\n    this.systemConfig\n      .updateNumberFieldSequence(type, rowData?.GUID!, table.dppRender.dParams?.['classficationFeatureItemguid']!)\n      .subscribe(res => {\n        if (res.success) {\n          this.dppMessageService.success('common.operation.operationSuccess');\n          const topTable = table['topTable'] as DppTableComponent;\n          topTable.refreshData().subscribe(res => {\n            const index = topTable\n              .getTreeNodes()\n              .findIndex(\n                (item: any) => item['origin']?.GUID === table.dppRender.dParams!['classficationFeatureItemguid']\n              );\n            topTable.setNodeSelected(index);\n          });\n          table.refreshData();\n        }\n      });\n  }"
