            "code": "  // 修改code子项\n  sysCodeItemModifyAction(event: EventInterface): void {\n    // eslint-disable-next-line @typescript-eslint/no-explicit-any\n    const rowData = this.getRowData(event) as any;\n    const com = event.contentComFn() as unknown as BaseComponent;\n    const masterGuid = rowData['MASTERGUID'];\n    const table = this.getContentCom(event) as unknown as DppTableComponent;\n    const targetNode = this.getNode(event) as RowNode;\n    // const parent = table.getFlatRootNodes();\n    const formParams: IFormRender = {\n      name: FormConfigModelEnum.NEWCODEITEMFORM,\n      mParams: {\n        mode: ModeTypeEnum.EDIT,\n        isObject: false\n      },\n      data: rowData as Record<string, unknown>\n    };\n    const modal = this.as.openModal(\n      {\n        title: 'systemSetting.codeManagement.commonTitle.editCodeItem',\n        width: '600px',\n        height: '230px',\n        closable: true,\n        openModalCloseDrawer: false,\n        content: DppFormComponent,\n        footer: [\n          {\n            label: 'common.button.reset',\n            type: 'default',\n            onClick: formCpn => {\n              formCpn.reset();\n            }\n          },\n          {\n            label: 'common.button.confirm',\n            type: 'primary',\n            onClick: formCpn => {\n              const currentTime = new Date();\n              const datePipe = new DatePipe('zh-CN');\n              const formatedDate = datePipe.transform(currentTime, 'yyyy-MM-dd HH:mm:ss', 'GMT+8');\n\n              const isValid = formCpn.onSubmit();\n              const formData = formCpn.getFormData();\n              formData['MASTERGUID'] = masterGuid;\n\n              if (isValid) {\n                formCpn.setLoading(true);\n                this.codeManagement.updateCodeItem(formData).subscribe({\n                  next: res => {\n                    formCpn.setLoading(false);\n                    if (res.success) {\n                      this.dppMessageService.success('common.operation.saveSuccess');\n                      targetNode.setData({\n                        ...targetNode.origin,\n                        ...res.data\n                      });\n                      modal.close();\n                    }\n                  },\n                  error: err => {\n                    formCpn.setLoading(false);\n                  }\n                });\n              }\n            }\n          }\n        ]\n      },\n      {\n        dppRender: formParams\n      }\n    );\n  }"
