            "code": "    // 编辑\n    sysSignatureSchemeEditAction(event: EventInterface): void {\n        const rowData = this.getRowData(event)\n        console.log('d', this.getRowData(event))\n        window.open(\n            `addParams?guid=${rowData['GUID']}&docWidth=${rowData['docWidthPx']}&docHeight=${rowData['docHeightPx']}&fileGuid=${rowData['fileGuid']}&name=${rowData['name']}&fileName=${rowData['fileName']}`\n        )\n    }"
