            "event_type": "event: EventInterface",
            "code": "    editTransferWorkflowTableAction(event: EventInterface): Observable<boolean> {\n        const table = event.contentComFn() as unknown as DppTableComponent\n        const data = table.getTreeNodes().map(item => {\n            return item.origin\n        })\n        this.WORKFLOWACTRTS = data\n        return of(true)\n    }"
