            "note": "// 移除已选可用对象",
            "code": "  // 移除已选可用对象\n  delAvailableObject: CustomObjectTagDelFn = item => {\n    let launchObjectMap = new Map<string, DppSafeAny>();\n    const launchScope = item.formCpm['data']['LAUNCH_SCOPE'] ?? [];\n    let current: CustObjectItem[] = [];\n    let delTitle: string[] = [];\n    let content = '你确定要移除该对象吗？';\n\n    // if (launchScope.length > 0) {\n    //   // 当前移除的可用对象boguid\n    //   const currentAvailableObBOGUID = item.tag.data.origin['BOGUID'];\n    //   launchScope.forEach((item: CustObjectItem) => {\n    //     launchObjectMap.set(item.origin['BOGUID'], item);\n    //     if (currentAvailableObBOGUID === item.origin['BOGUID']) {\n    //       current.push(item);\n    //     }\n    //   });\n\n    //   // 处理可移除de可发起对象\n    //   if (current.length > 0) {\n    //     let title = '';\n    //     current.forEach(ele => {\n    //       delTitle.push(this.dpptranslate.transform(ele.title));\n    //     });\n    //     title = delTitle.join(';');\n    //     content = '移除该可用对象后，以下可发起对象也将同时移除: <br/>' + title;\n    //   }\n    // }\n\n    const deleteObj = (): void => {\n      item.field.onItemDelete(item.tag.data, 'GUID');\n      if (current.length > 0) {\n        current.forEach(ele => {\n          item.formCpm.getService().getFieldCpmByKey<FieldObjectComponent>('LAUNCH_SCOPE').onItemDelete(ele, 'GUID');\n          launchObjectMap.delete(content);\n        });\n      }\n      this.dppMessageService.success('common.operation.removeSucceed');\n    };\n\n    const modal = this.as.confirm(content, {\n      title: '警告',\n      footer: {\n        nzOnOk: () => deleteObj(),\n        nzOnCancel: () => modal.close()\n      }\n    });\n  };",
            "toRemove": true
