            "lines": 54,
            "event_type": "event: EventInterface",
            "code": "  sysDCNodeManagEditAction(event: EventInterface): void {\n    const rowData = this.getRowData(event)\n    const id = rowData['id']\n    const table = this.getContentCom(event) as unknown as DppTableComponent\n    this.dispatchCenterService.getNodeInfo(id).subscribe(res => {\n      const data = res.data\n      const formParams: IFormRender = {\n        name: 'sysDCNewNodeManageFrom',\n        mParams: { mode: ModeTypeEnum.EDIT, isObject: false },\n        dParams: {},\n        data\n      };\n      const modal = this.as.openModal(\n        {\n          title: '编辑节点',\n          width: '800px',\n          height: '400px',\n          closable: true,\n          content: DppFormComponent,\n          openModalCloseDrawer: false,\n          footer: [\n            {\n              label: 'common.button.cancel',\n              type: 'default',\n              onClick: formCpn => {\n                formCpn.reset();\n                modal.close();\n              }\n            },\n            {\n              label: 'common.button.confirm',\n              type: 'primary',\n              onClick: formCpn => {\n                let isValid = formCpn.onSubmit();\n                const formData = formCpn.getFormData();\n                if (isValid) {\n                  this.dispatchCenterService.updateNode(formData).subscribe((res) => { \n                    if (res.success) {\n                      this.messageService.success('common.operation.operationSuccess')\n                      modal.close()\n                      table.refreshData()\n                    }\n                  })\n                }\n              }\n            }\n          ]\n        },\n        {\n          dppRender: formParams\n        }\n      );\n    })\n  }"
