            "code": "  // 删除子阶业务对象\n  deleteRelationTemplateEnd2Action(event: EventInterface): void {\n    // eslint-disable-next-line @typescript-eslint/no-explicit-any\n    const rowData = this.getRowData(event) as any;\n    // eslint-disable-next-line @typescript-eslint/no-explicit-any\n    const memberInstance = event.exeComFn() as any;\n    const deleteEND2BONAME = memberInstance['removedTag'].END2BONAME;\n    const End2List: Array<{ END2GUID: string }> = [];\n    // eslint-disable-next-line @typescript-eslint/no-explicit-any\n    rowData.relationTemplateEnd2List.forEach((res: any) => {\n      if (res.END2BONAME !== deleteEND2BONAME) {\n        End2List.push({\n          END2GUID: res.END2BONAME\n        });\n      }\n    });\n    const GUID = rowData.GUID;\n    this.relationManagement.updateRelationEnd2(GUID, End2List).subscribe(res => {\n      this.dppMessageService.success(' common.operation.deleteSuccess');\n    });\n\n    // End2List =\n    // this.relationManagement.updateRelationEnd2(GUID).subscribe(res => {\n    // });\n  }"
