            "id": "pdm_c0_7",
            "name": "sysBomCompareFilterPassesAction",
            "lines": 11,
            "event_type": "TableUndefined",
            "code": "  sysBomCompareFilterPassesAction(event: ExtendFilterEvent): boolean {\n    // 仅生效\n    const table = (event.node['beans'] as BeanCollections).table;\n    if (table['onlyDiffer']) {\n      const sort = table.queryCondition.params.get('SORT') as string | undefined;\n      const data = event.node.origin;\n      return this.isRowDifferent(data, sort, table);\n    } else {\n      return true;\n    }\n  }",
