            "code": "  // bom派生表格 点击复选框后的动作\n  sysBomForkCheckboxAction(event: EventInterface): void {\n    const tableCpm = this.getContentCom<DppTableComponent>(event);\n    const selectNode = tableCpm.getCheckedNodes();\n    const isRoot = selectNode.some(i => i.origin['ISROOT'] === 'Y');\n    const isAllow = !selectNode.some(i => i.origin['ISALLOWDERIVE'] === 'N');\n    const floatToolbar = tableCpm.beans.floatToolbarCtrl.getToolbarInstance()!;\n    floatToolbar.callback({\n      params: {\n        //@ts-ignore\n        ISROOT: isRoot ? 'Y' : 'N',\n        ISALLOWDERIVE: isAllow\n      }\n    });\n  }"
