            "code": "  // 单元格保存\n  sysBomForkCellAction(event: TableCellEvent): Observable<any> | void {\n    // const tableCpm = this.getContentCom<DppTableComponent>(event);\n    const tableCpm = this.getContentCom<DppTableComponent>(event);\n\n    const { editChancedRowData } = event;\n    const params = BomDerivationUtil.buildBomForkUpdateParams(event.data, BomForkType.edit, editChancedRowData!);\n    return this.bomForkService.batchEditDeriveStructure([params]).pipe(\n      // map(i => {\n      //   if (i.data?.errorCnt !== 0) {\n      //     this.message.error(i.data?.details[0].message!);\n      //     return [];\n      //   }\n      //   return i.data.details[0].data;\n      // }),\n      map(i => {\n        const batchEventParams: BomForkBatchParams = {\n          tableCpm,\n          batchDatas: i.data!,\n          message: this.message,\n          event,\n          option: '编辑'\n        };\n        BomDerivationUtil.batchHandle(batchEventParams);\n        const tempData: DppResponse<any> = {\n          errorCode: '',\n          errorMsg: '',\n          success: true,\n          data: {}\n        };\n        return tempData;\n      })\n    );\n  }"
