            "note": "bom派生表格 操作列 移除按钮",
            "code": "  // bom派生表格 操作列 移除按钮\n  sysBomForkOperaDelAction(event: EventInterface): void {\n    const rowData = this.getRowData(event);\n    const rowNode = this.getNode(event) as RowNode;\n    const page = this.getRootPageService(event);\n    const tableCpm = this.getContentCom<DppTableComponent>(event);\n    const tabFormCpm = page.getComFnMapByName<TabFormComponent>(BomForkCommandConstant.tabFormCommand)!;\n    this.setLoading(event, true);\n    const params = BomDerivationUtil.buildBomForkUpdateParams(rowData, BomForkType.del);\n    this.bomForkService\n      .batchEditDeriveInfo([params])\n      .pipe\n      // map(i => {\n      //   if (i.data?.errorCnt !== 0) {\n      //     this.message.error(i.data?.details[0].message!);\n      //     return [];\n      //   }\n      //   return i.data.details[0].data;\n      // })\n      ()\n      .subscribe({\n        next: res => {\n          const batchEventParams: BomForkBatchParams = {\n            tableCpm,\n            batchDatas: res.data!,\n            message: this.message,\n            event,\n            option: i18n_BOM_Fork.CANCEL\n          };\n          BomDerivationUtil.batchHandle(batchEventParams);\n          tabFormCpm.removeForkPage(rowData);\n          if (rowNode.origin['HASEND2'] && rowNode.isExpanded) {\n            tableCpm.refreshData(rowNode);\n          }\n          this.setLoading(event, false);\n        },\n        error: err => {\n          this.setLoading(event, false);\n        }\n      });\n  }",
            "toRemove": true
