            "code": "  // bom派生表格 浮动toolbar 保存\n  sysBomForkBatchSaveAction(event: EventInterface): void {\n    const tableCpm = this.getContentCom<DppTableComponent>(event);\n    const selectNodes = tableCpm.getCheckedNodes();\n\n    const sourceList = selectNodes\n      // 只需要派生且是未保存的\n      .filter(i => i.origin[BomForkKey.bomForkType] === BomForkType.fork && i.origin[BomForkKey.bomForkUpdate] !== 'Y')\n      .map(i => {\n        // const item: BatchSetValueParams = {\n        //   guid: i.origin[SystemClassFieldEnum.GUID],\n        //   className: i.origin[SystemClassFieldEnum.CLASSNAME],\n        //   end2: {\n        //     guid: i.origin[`END2#${SystemClassFieldEnum.GUID}`],\n        //     className: i.origin[`END2#${SystemClassFieldEnum.CLASSNAME}`]\n        //   },\n        //   props: {}\n        // };\n        // itemList.push(item);\n        return BomDerivationUtil.buildBomForkUpdateParams(i.origin, BomForkType.fork);\n      });\n\n    if (sourceList.length === 0) {\n      this.message.warning(i18n_BOM_Fork.FORK_NOT_SAVE_WARNING);\n      return;\n    }\n\n    this.setLoading(event, true);\n    this.bomForkService.batchEditDeriveInfo(sourceList).subscribe({\n      next: res => {\n        this.setLoading(event, false);\n\n        if (!res.success) {\n          this.setLoading(event, false);\n          return;\n        }\n\n        const batchEventParams: BomForkBatchParams = {\n          tableCpm,\n          batchDatas: res.data!,\n          message: this.message,\n          event\n        };\n        BomDerivationUtil.batchHandle(batchEventParams);\n        this.setLoading(event, false);\n      },\n      error: err => {\n        this.setLoading(event, false);\n      }\n    });\n  }"
