            "code": "  // bom派生表格 新增\n  sysBomForkAddChildNodeAction(event: EventInterface): void {\n    const bs = this.getExeCom<DppButtonComponent>(event);\n    const action = { ...bs.getUiModel().action! };\n    const tableCpm = this.getContentCom<DppTableComponent>(event);\n    const templateName = tableCpm.modelManager.rootInfo?.params['ROOTTEMPLATENAME'] as string;\n    const render = assembParams({\n      action\n    });\n    const rowNode = this.getNode(event) as RowNode;\n    const rowData = this.getRowData(event);\n    render.dParams = render.dParams ?? {};\n    render.dParams.guid = rowData[BomForkKey.end2Key];\n    render.dParams.className = rowData[BomForkKey.end2ClassName];\n    render.dParams.classGuid = rowData[BomForkKey.end2Class];\n    CommonEventUtil.buildModal<DppTableComponent>({\n      event,\n      message: this.message,\n      cpmParams: { dppRender: render },\n      footers: [\n        {\n          label: 'common.button.confirm',\n          type: 'primary',\n          onClick: (button, modalTableCpm, modal) => {\n            const selectNodes = modalTableCpm.getCheckedNodeList();\n\n            if (selectNodes.length == 0) {\n              this.message.warning('common.operation.noDataSelected');\n              return;\n            }\n\n            const checkOutValue = rowData[BomForkKey.viewCheckout];\n\n            let checkout$: Observable<boolean> = of(true);\n\n            // if ([undefined, 'N'].includes(checkOutValue)) {\n            //   checkout$ = this.relation\n            //     .batchCheckBOMView(\n            //       [{ guid: rowData[BomForkKey.end2Key], className: rowData[BomForkKey.end2ClassName] }],\n            //       templateName,\n            //       'checkOut'\n            //     )\n            //     .pipe(\n            //       map(res => {\n            //         const dppUser = this.authService.getUser()!;\n            //         const userID = dppUser.guid || '';\n            //         const userName = dppUser.userName || '';\n\n            //         const viewValue = rowNode.origin['VIEW#ISCHECKOUT$'];\n            //         const state = viewValue ? rowNode.origin['VIEW#STATUS$'] : 'WIP';\n\n            //         let refreshData = {\n            //           'VIEW#ISCHECKOUT$': 'Y',\n            //           'VIEW#CHECKOUTUSER$': userID,\n            //           'VIEW#CHECKOUTUSER$NAME': userName,\n            //           'VIEW#STATUS$': state,\n            //           ISEDIT$: true\n            //         };\n            //         tableCpm.refreshNode(rowNode, refreshData);\n            //         return true;\n            //       })\n            //     );\n            // }\n            // ROOTGUID: tableCpm.dppRender.dParams?.guid!,\n            // SOURCEDERIVEGUID: rowData[BomForkKey.derKey] || '',\n            // REPLACEGUID: selectNode.origin[SystemClassFieldEnum.GUID],\n            // REPLACECLASSGUID: selectNode.origin[SystemClassFieldEnum.CLASSGUID],\n            // SOURCETEMPLATENAME: templateName\n            const params = selectNodes.map(i => {\n              const param: BomForkAddParams = {\n                INSERTGUID: i.origin[SystemClassFieldEnum.GUID],\n                INSERTCLASSGUID: i.origin[SystemClassFieldEnum.CLASSGUID],\n                INSERTTEMPLATENAME: templateName\n              };\n              return param;\n            });\n            const rootGuid = tableCpm.dppRender.dParams!.guid!;\n            const sourceDeriveGuid = rowData[BomForkKey.derKey];\n            button.loading = true;\n            this.setLoading(event, true);\n\n            checkout$\n              .pipe(switchMap(i => this.bomForkService.insertDeriveRecord(rootGuid, sourceDeriveGuid, params)))\n              .subscribe({\n                next: res => {\n                  const batchEventParams: BomForkBatchParams = {\n                    tableCpm,\n                    batchDatas: res.data!,\n                    message: this.message,\n                    event\n                  };\n                  BomDerivationUtil.batchHandle(batchEventParams);\n                  tableCpm.refreshData(rowNode);\n                  button.loading = false;\n                  this.setLoading(event, false);\n                  modal.close();\n                },\n                error: err => {\n                  button.loading = false;\n                  this.setLoading(event, false);\n                }\n              });\n          }\n        }\n      ]\n    });\n  }"
