            "code": "  // 派生历史记录 BOM比较\n  sysBomForkBomComparisonAction(event: EventInterface): void {\n    const tableCpm = this.getContentCom<DppTableComponent>(event);\n    const rowData = this.getRowData(event);\n\n    // const property = {\n    //   uiType: 'page',\n    //   routePath: '/page?name=sysBomComparePage',\n    //   name: 'sysBomComparePage'\n    // };\n    // const params = {\n    //   dppRender: {\n    //     // guid: new Date().getTime().toString()，\n    //     dParams: {\n    //       bom1Guid: 'F25EBBFC57A841E6A3B439B6E0B9A959',\n    //       bom1ClassName: 'Part',\n    //       bom2Guid: '4AF0625BCECA4F5C951F53909D4B71D0',\n    //       bom2ClassName: 'Part'\n    //     }\n    //   }\n    // };\n\n    const button = this.getExeCom<DppButtonComponent>(event);\n    const params: RouteUrlKeyParams = {\n      model: button.getUiModel().action,\n      data: {\n        ...rowData,\n        dParams: tableCpm.dppRender.dParams\n      },\n    }\n    const routeUi = this.routeService.getRouteUIByKey(button.getUiModel().action['route'])!\n    const tranParams = DppTargetRouteUtil.parseUrlKey(params);\n    const routePath = DppTargetRouteUtil.getRouteQueryString({ routeUi, tranParams })\n    const property = {\n      title: routePath,\n      routePath\n    };\n    this.as.openBlank(property);\n  }"
