            "code": "  sysECMSavePerformerAction(event: EventInterface): void {\n    const rowData = this.getRowData(event);\n    // if (rowData[SystemClassFieldEnum.ISCHECKOUT] !== 'Y') {\n    //   // guess ? table!.setLoading(false) : this.setLoading(event, false);\n    //   this.message.warning('backend.business.message.notCheckout');\n    //   return;\n    // }\n    // this.setLoading(event, true);\n    const bs = event.exeComFn() as DppButtonComponent;\n    const action = bs.getUiModel().action!;\n    const instanceData = this.getRootPageService(event).getInstanceData();\n    const checkOutParams: CheckOutParams = {\n      iFound: instanceData,\n      authUser: this.authUserService,\n      messageService: this.message,\n      eco: rowData,\n      type: 'assign'\n    };\n    const isValidCheckOut = EcmEventUtil.isValidCheckOut(checkOutParams);\n    if (!isValidCheckOut) {\n      return;\n    }\n    // 暂时不知道key\n    const currentPerformer = rowData['PERFORMER'];\n    (action.width = '600px'), (action.ui = 'userList'), (action.height = '350px');\n\n    const modal = CommonEventUtil.buildDefaultModal<UserListComponent>(\n      event,\n      (okButtonThis, userListComponent) => {\n        okButtonThis.loading = true;\n        const selectedData = userListComponent.getSelectedData() as ListNode;\n        const item = { GUID$: rowData['GUID$'], CLASSGUID$: rowData['CLASSGUID$'], CLASSNAME$: rowData['CLASSNAME$'] };\n        if (selectedData) {\n          if (selectedData.GUID === currentPerformer) {\n            okButtonThis.loading = false;\n            this.message.warning('common.operation.unmodifiedData');\n            return;\n          }\n          this.ecm.savePerformer([item], selectedData.GUID!).subscribe(\n            res => {\n              if (res.success && res.success) {\n                if (res!.data!.totalCnt === res!.data!.successCnt) {\n                  this.message.success('common.operation.operationSuccess');\n                  this.contentComCallback(\n                    event,\n                    CommonEventUtil.buildCallBack(undefined, undefined, EventCallbacksActionName.UPDATE)\n                  );\n                } else {\n                  this.message.error(res.data?.details[0].message!);\n                }\n                modal.close();\n              } else {\n                this.message.warning(`${res.errorCode}:${res.errorMsg}`);\n              }\n              this.setLoading(event, false);\n            },\n            error => {\n              okButtonThis.loading = false;\n              this.setLoading(event, false);\n            }\n          );\n        } else {\n          this.message.warning('common.operation.noDataSelected');\n          okButtonThis.loading = false;\n          // this.setLoading(event, false);\n        }\n      },\n      this.message,\n      { key: currentPerformer ? currentPerformer : '' },\n      false\n    );\n  }"
