            "note": "ECO 基础信息上的启动",
            "code": "  // ECO 基础信息上的启动\n  sysECOStartEcoAction(event: EventInterface): void {\n    const rowData = this.getRowData(event);\n    let rightPage: DppPageComponent | undefined;\n    if (rowData[SystemClassFieldEnum.CLASSNAME].includes('Batch')) {\n      rightPage = this.formRootFindChild<DppPageComponent>(event, CommandConstant.ECORightBatchCommand);\n    } else {\n      rightPage = this.formRootFindChild<DppPageComponent>(event, CommandConstant.ECORightNormalCommand);\n    }\n    EcmEventUtil.updateEcoStatus(event, rowData, 'start', this.ecm, this.message, res => {\n      if (res.success) {\n        this.message.success('common.operation.operationSuccess');\n        // const callBackData = CommonEventUtil.buildCallBack(undefined, EventCallbacksActionName.REFRESHDATA);\n        // CommonEventUtil.contentComCallback(event, callBackData);\n        // this.getRootPageService(event).refreshInstanceData({\n        //   callback: resData => {\n        //     this.contentComCallback(event, CommonEventUtil.buildCallBack(resData, EventCallbacksActionName.UPDATE));\n        //     if (rowData[SystemClassFieldEnum.CLASSNAME].includes('Batch')) {\n        //       EcmEventUtil.refreshRightPageInBatchECO(rightPage!);\n        //     } else {\n        //       EcmEventUtil.refreshRightPageInECO(rightPage!, resData);\n        //     }\n        //   }\n        // });\n        this.getRootPageService(event).refreshInstanceData({ isRefreshSelf: true });\n        // window.location.reload();\n      } else {\n        this.message.warning(`${res.errorCode}:${res.errorMsg}`);\n      }\n      CommonEventUtil.setLoading(event, false);\n    });\n  }"
