            "code": "  // 影响分析 分段器\n  sysEcImpactAnalysisSelectAction(event: EventInterface): void {\n    const table = this.getContentCom<DppTableComponent>(event);\n    const params = Object.fromEntries(table.queryCondition.params);\n    params['analysisType'] = event.event;\n    table.refreshByParams(params);\n  }"
