            "event_type": "event: EventInterface",
            "note": "工序添加",
            "code": "  // 工序添加\n  ProcessAddRelatedAction(event: EventInterface): void {\n    const bs = this.getExeCom<DppButtonComponent>(event);\n    const table = this.getContentCom<DppTableComponent>(event) as DppTableComponent;\n    const tableName = table.dppRender.name!.replace(/(\\w+)(Table)/g, '$1Search$2');\n    const { className, guid, templateName } = CommonEventUtil.getTableMess(table);\n    const buttonModel: IButtonUiModel = this.getExeModel(event) as IButtonUiModel; // 不能从按钮里拿哦\n    const tableData = table.getTreeNodes(); // 点击添加那一层的表格数据\n    // eslint-disable-next-line @typescript-eslint/no-this-alias\n    const that = this;\n    const modal = this.as.openModal(\n      {\n        title: buttonModel.label,\n        uiType: 'search',\n        full: true,\n        // content: DppTableComponent,\n        footer: [\n          {\n            label: 'basic.common.button.confirm',\n            type: 'primary',\n            onClick(globalSearch: DppGlobalSearchComponent) {\n              this.loading = true;\n              const checkNodes = globalSearch.table.getCheckedNodes();\n              const data = checkNodes.map(item => {\n                return item.origin;\n              }) as unknown as IFoundaton[];\n              if (!data.length) {\n                that.dppMessageService.warning('common.operation.noDataSelected');\n                this.loading = false;\n                return;\n              }\n              this.loading = false;\n              modal.close();\n              addRelation(data);\n            }\n          }\n        ]\n      },\n      {\n        dppRender: {\n          name: tableName,\n          dParams: {\n            templateName,\n            className,\n            guid\n          },\n          mParams: {\n            name: tableName,\n            // toolbar: 'searchToolbar',\n            property: {\n              submit: 'true',\n              type: 'ui'\n            },\n            description: 'ItemManagerCommand',\n            initShow: 'false',\n            ui: 'table',\n            type: 'ui',\n            menuDataSource: `/Common/IAdvSearchService/listMenuItemsForRelationChildAdd?relationTemplateNames=${templateName}&END1$CLASSNAME$=${className}&END1$=${guid}`,\n            dataSource: `/Common/IAdvSearchService/listItemsForRelationChildAdd ?relationTemplateNames=${templateName}&END1$CLASSNAME$=${className}&END1$=${guid}`,\n            label: 'basic.common.command.ItemManagerCommand',\n            modelType$: 'command'\n          }\n        }\n      }\n    );\n\n    const addRelation = (data: IFoundaton[]) => {\n      const param: Structure[] = [];\n      console.log('d', data);\n      if (!data?.length) {\n        return;\n      }\n      const repeatData = data.filter(item =>\n        tableData.some((element: RowNode) => item.GUID$ === element.origin?.['GUID$'])\n      );\n      const filterData = data.filter(\n        item => !tableData.some((element: RowNode) => item.GUID$ === element.origin?.['GUID$'])\n      );\n      if (repeatData.length > 0 && filterData.length === 0) {\n        this.dppMessageService.warning('common.operation.addDataDuplicate');\n        return;\n      }\n      filterData.forEach(selectedData => {\n        const end2 = {\n          guid: selectedData.GUID$,\n          classGuid: selectedData.CLASSGUID$,\n          className: selectedData.CLASSNAME$\n        };\n        param.push({\n          end2: end2,\n          props: {},\n          modifyType: ModifyEnum.ADD\n        });\n      });\n      const relation = {\n        end1: {\n          className,\n          guid\n        },\n        templateName,\n        isBOM: false,\n        structures: param\n      };\n      const isBeUsed = table.dppRender.dParams?.['isBeUsed'];\n      const isAddChild = isBeUsed && isBeUsed === 'N';\n\n      this.relationService.batchOperatebatchLinkActive(relation, isAddChild).subscribe({\n        next: res => {\n          if (res.success) {\n            if (res.data) {\n              // 总数量 成功数量  失败数量\n              const { successCnt, totalCnt, errorCnt } = res.data;\n              if (successCnt === totalCnt) {\n                // this.dppMessageService.success('common.operation.operationSuccess');\n                if (repeatData.length > 0 && filterData.length > 0) {\n                  this.dppMessageService.success('common.operation.addSuccessAndDeduplicated');\n                } else {\n                  this.dppMessageService.success('common.operation.addRelatedSuccess');\n                }\n              } else {\n                this.errMessageService.showMessage(event, res);\n              }\n              this.contentComCallback(event, {\n                operate: EventCallbacksActionName.UPDATE\n              });\n            }\n          }\n        }\n      });\n    };\n  }"
