            "lines": 183,
            "event_type": "event: EventInterface",
            "note": "从bom添加",
            "code": "  // 从bom添加\n  AddBOMRelatedAction(event: EventInterface): void {\n    const table = this.getContentCom<DppTableComponent>(event);\n    const { className, guid, templateName } = CommonEventUtil.getTableMess(table);\n\n    // 高级搜索确定事件\n    const onGlobalSearchOk = (globalSearch: DppGlobalSearchComponent, globalSearchModal: DppNzModalRef): void => {\n      const checkedNodeList = globalSearch.table.getCheckedNodeList();\n      if (!checkedNodeList || checkedNodeList.length === 0) {\n        this.dppMessageService.warning('common.operation.noDataSelected');\n        return;\n      }\n      globalSearchModal.close();\n      const selectData = checkedNodeList[0]['origin'] as IFoundaton;\n      openSelectTable(selectData);\n    };\n    // 选择弹窗确定事件\n    const onSelectOk = (\n      selectTable: DppTableComponent,\n      selectModal: DppNzModalRef,\n      setLoading: (loading: boolean) => void\n    ): void => {\n      const end2Datas = selectTable.getCheckedNodeList();\n      if (!end2Datas || end2Datas.length === 0) {\n        this.dppMessageService.warning('common.operation.noDataSelected');\n        setLoading(false);\n        return;\n      }\n      const param: Structure[] = [];\n      end2Datas.forEach(end2Data => {\n        if (!end2Data['origin']) {\n          return;\n        }\n\n        const end2 = {\n          guid: end2Data['origin']['END2#GUID$'],\n          classGuid: end2Data['origin']['END2#CLASSGUID$'],\n          className: end2Data['origin']['END2#CLASSNAME$']\n        };\n        param.push({\n          end2: end2,\n          props: {},\n          modifyType: ModifyEnum.ADD\n        });\n      });\n      const relation = {\n        end1: {\n          className,\n          guid\n        },\n        templateName,\n        isBOM: false,\n        structures: param\n      };\n      this.relationService.batchOperateActive(relation, ModifyEnum.ADD).subscribe({\n        next: res => {\n          if (res.data!.totalCnt === res.data!.successCnt) {\n            this.dppMessageService.success('common.operation.addRelatedSuccess');\n            setLoading(false);\n            selectModal.close();\n          } else {\n            const bs = this.getExeCom<DppButtonComponent>(event);\n            this.dppMessageService.createTableMessage('warning', bs.getUiModel().label, res.data!);\n            setLoading(false);\n          }\n          this.contentComCallback(event, {\n            operate: EventCallbacksActionName.UPDATE\n          });\n        },\n        error: err => {\n          setLoading(false);\n        }\n      });\n    };\n    // 打开后续选择弹窗  @order 2\n    const openSelectTable = (selectData: IFoundaton): void => {\n      const selectModal = this.as.openModal(\n        {\n          title: 'common.command.sysCommonAddCommand',\n          width: '80vw',\n          content: DppTableComponent,\n          bodyStyle: { height: '600px' },\n          footer: [\n            {\n              label: 'common.button.cancel',\n              type: 'default',\n              onClick() {\n                selectModal?.close();\n              }\n            },\n            {\n              label: 'common.button.confirm',\n              type: 'primary',\n              onClick(selectTable: DppTableComponent) {\n                const setLoading = (loading: boolean): void => {\n                  this.loading = loading;\n                };\n                setLoading(true);\n                onSelectOk(selectTable, selectModal, setLoading);\n              }\n            }\n          ]\n        },\n        {\n          dppRender: {\n            name: 'sysProcessMainItemAddStructureTable',\n            dParams: {\n              CLASSNAME$: selectData['CLASSNAME$'],\n              GUID$: selectData['GUID$']\n            },\n            mParams: {\n              hasClose: 'true',\n              type: 'modal',\n              titleExpression:\n                \"'【' +(${BOTITLE$}?${BOTITLE$}:${END2#BOTITLE$})+'】' + (${FULLNAME$}?${FULLNAME$}:${END2#FULLNAME$})+' (维护产品结构)'\",\n              mode: 'view',\n              hasOk: 'true',\n              ui: 'table',\n              rootSource: '/ItemManagement/IBomService/listRoot?GUID$=$GUID$&className=$CLASSNAME$&templateName=BOM',\n              name: 'sysMaintainProductStructureTable',\n              width: '78vw',\n              dataSource:\n                '/ItemManagement/IBomService/listBOM?templateName=BOM&guid=$END2#GUID$&className=$END2#CLASSNAME$&level=$expandLevel',\n              height: '580px'\n            }\n          }\n        }\n      );\n    };\n    // 打开高级搜索弹窗  @order 1\n    const openGlobalSearch = (): void => {\n      const globalSearchModal = this.as.openModal(\n        {\n          title: 'common.command.sysCommonAddCommand',\n          uiType: 'search',\n          full: true,\n          footer: [\n            {\n              label: 'common.button.cancel',\n              type: 'default',\n              onClick() {\n                globalSearchModal?.close();\n              }\n            },\n            {\n              label: 'common.button.confirm',\n              type: 'primary',\n              onClick(globalSearch: DppGlobalSearchComponent) {\n                onGlobalSearchOk(globalSearch, globalSearchModal);\n              }\n            }\n          ]\n        },\n        {\n          dppRender: {\n            name: 'ItemManageSearchSingleTable',\n            dParams: {\n              templateName,\n              className,\n              guid\n            },\n            mParams: {\n              name: 'ItemManageSearchSingleTable',\n              // toolbar: 'searchToolbar',\n              property: {\n                submit: 'true',\n                type: 'ui'\n              },\n              description: 'ItemManagerCommand',\n              initShow: 'false',\n              ui: 'table',\n              type: 'ui',\n              menuDataSource: `/Common/IAdvSearchService/listMenuItemsForRelationChildAdd?relationTemplateNames=${templateName}&END1$CLASSNAME$=${className}&END1$=${guid}`,\n              dataSource: `/Common/IAdvSearchService/listItemsForRelationChildAdd ?relationTemplateNames=${templateName}&END1$CLASSNAME$=${className}&END1$=${guid}`,\n              label: 'basic.common.command.ItemManagerCommand',\n              modelType$: 'command'\n            }\n          }\n        }\n      );\n    };\n\n    openGlobalSearch();\n  }"
