            "code": "  /**\n   * 制造大纲工艺流程组成添加工序事件\n   * @param event\n   */\n  sysFabricationOutlineProcessFlowConstituteAddAction(event: EventInterface): void {\n    const render = {\n      name: 'sysFabricationOutlineProcessFlowConstituteAddTable',\n      mParams: {\n        toolbar: 'sysFabricationOutlineProcessFlowConstituteProcessAddToolBar',\n        // dataSource: '/Common/ICommonService/listObject?interfaceNames=$interfaceNames'\n        dataSource: '/Common/IAdvSearchService/listItemsForInterfaceSearch?interfaceNames=$interfaceNames'\n      },\n      dParams: {\n        interfaceNames: 'IFabricationProcess'\n      }\n    };\n    // eslint-disable-next-line @typescript-eslint/no-this-alias\n    const that = this;\n    const modal = this.as.openModal(\n      {\n        title: 'process.operation.fabricationOutlineSelect',\n        width: '80vw',\n        height: '600px',\n        content: DppTableComponent,\n        footer: [\n          {\n            label: 'common.button.cancel',\n            type: 'default',\n            onClick: (): void => {\n              modal.close();\n            }\n          },\n          {\n            label: 'common.button.confirm',\n            type: 'primary',\n            onClick(data) {\n              this.loading = true;\n              const addTable = data as DppTableComponent;\n              const pageService = that.getRootPageService(event);\n              const table = pageService.getComFnMapByName(\n                'sysFabricationOutlineProcessFlowConstituteCommand'\n              ) as DppTableComponent;\n              const exeCom = that.getExeCom(event) as DppButtonComponent;\n              const end1Iinstance = exeCom.dppRender?.['config']?.['innerSend']?.['instanceData'];\n              const checkedNodesInfo = addTable.getCheckedNodes();\n              if (checkedNodesInfo && checkedNodesInfo.length > 0) {\n                let end1: { guid: string; className: string } = {\n                  className: end1Iinstance?.['CLASSNAME$']!?.toString(),\n                  guid: end1Iinstance?.['GUID$']!?.toString()\n                };\n                let STRUCTURES: Array<{\n                  end2: { guid: string; className: string };\n                  props: Record<string, unknown>;\n                  modifyType: string;\n                }> = [];\n                checkedNodesInfo?.forEach(item => {\n                  STRUCTURES.push({\n                    end2: { className: item?.['origin']?.['CLASSNAME$']!, guid: item?.['origin']?.['GUID$']! },\n                    props: {},\n                    modifyType: 'ADD'\n                  });\n                });\n                const relation = {\n                  end1: end1,\n                  structures: STRUCTURES\n                };\n                that.processManagementService.batchLinkFabProcess(relation).subscribe({\n                  next: res => {\n                    if (res.success) {\n                      that.dppMessageService.success('common.operation.operationSuccess');\n                      table.refreshData();\n                      this.loading = false;\n                      modal.close();\n                    }\n                  },\n                  error: err => {\n                    this.loading = false;\n                  }\n                });\n              } else {\n                this.loading = false;\n                that.dppMessageService.warning('common.operation.noDataSelected');\n              }\n            }\n          }\n        ]\n      },\n      { dppRender: render }\n    );\n  }"
