            "event_type": "_event: EventInterface",
            "note": "@description 产品设计 添加子任务 @use 产品设计/产品管理/任务管理-任务实例界面-子任务-添加 @param _event",
            "code": "  /**\n   * @description 产品设计 添加子任务\n   * @use 产品设计/产品管理/任务管理-任务实例界面-子任务-添加\n   * @param _event\n   */\n  sysAddDeliverablesAddAction(_event: EventInterface): void {\n    this.menuService;\n  }"
