            "event_type": "event: EventInterface",
            "note": "编辑产品库",
            "code": "  // 编辑产品库\n  sysEditProductLibraryAction(event: EventInterface): void {\n    const data = this.getRowData(event);\n    const formParams: IFormRender = {\n      mParams: {\n        mode: ModeTypeEnum.EDIT,\n        isObject: false\n      },\n      name: FormConfigModelEnum.EDITPRODUCTFORM,\n      data: data as Record<string, unknown>\n    };\n    const table = this.getContentCom(event) as unknown as DppTableComponent;\n    const bs = this.getExeCom(event) as DppButtonComponent;\n\n    const modal = this.as.openModal(\n      {\n        title: bs.getUiModel().label,\n        width: '650px',\n        height: 'auto',\n        closable: true,\n        content: DppFormComponent,\n        footer: [\n          {\n            label: 'common.button.reset', // 按钮文本\n            type: 'default',\n            size: 'default', // 大小\n            onClick: formCpn => {\n              formCpn.reset();\n            }\n          },\n          {\n            label: 'common.button.confirm', // 按钮文本\n            type: 'primary',\n            size: 'default', // 大小\n            onClick: formCpn => {\n              const isValid = formCpn.onSubmit();\n              const tranObj = formCpn.getFormData();\n              let request = new Observable<DppResponse<IFoundaton>>();\n\n              if (isValid) {\n                const formData = new FormData();\n                formCpn.setLoading(true);\n                if (!isEmpty(tranObj.FILEPROPS$) && !isEmpty(tranObj.DWFILES)) {\n                  if (tranObj.DWFILES.length > 0) {\n                    tranObj.DWFILES.forEach((file: any) => {\n                      delete file.url;\n                      const clonedFile = new File([file], file.uid, {\n                        type: file.type\n                      });\n                      formData.append('dwFile', clonedFile);\n                    });\n                  }\n                  formData.append('object', JSON.stringify(tranObj));\n                  request = this.productDesignService.saveLibrary(formData as unknown as Record<string, string>, true);\n                } else {\n                  // tranObj.DWFILES = [];\n                  // formData.append('object', JSON.stringify(tranObj));\n                  // request = this.productDesignService.saveLibrary(\n                  //   {\n                  //     DESCRIPTION: tranObj['DESCRIPTION'],\n                  //     FOLDERNAME: tranObj['FOLDERNAME'],\n                  //     TEMPLATEGUID: tranObj['TEMPLATEGUID']\n                  //   },\n                  //   false\n                  // );\n                  request = this.productDesignService.saveLibrary(tranObj, false);\n                }\n                request.subscribe({\n                  next: res => {\n                    if (res.success) {\n                      this.dppMessageService.success('common.operation.operationSuccess');\n                      table.refreshData();\n                      modal.close();\n                    }\n                    formCpn.setLoading(false);\n                  },\n                  error: _err => {\n                    formCpn.setLoading(false);\n                  }\n                });\n              }\n            }\n          }\n        ]\n      },\n      {\n        dppRender: formParams\n      }\n    );\n  }"
