            "note": "编辑模板",
            "code": "  // 编辑模板\n  sysTemplateManageEditAction(event: EventInterface): void {\n    const rowData = this.getRowData(event);\n    const formParams: IFormRender = {\n      name: FormConfigModelEnum.EditTemplateForm,\n      // name: 'sysEditTemplateForm',\n      mParams: {\n        mode: ModeTypeEnum.EDIT,\n        isObject: false\n      },\n      data: rowData as Record<string, unknown>\n    };\n    const table = this.getContentCom(event) as unknown as DppTableComponent;\n    const bs = this.getExeCom(event) as DppButtonComponent;\n    // eslint-disable-next-line @typescript-eslint/no-this-alias\n    const that = this;\n\n    const modal = this.as.openModal(\n      {\n        title: bs.getUiModel().label,\n        height: 'auto',\n        width: '600px',\n        closable: true,\n        content: DppFormComponent,\n        footer: [\n          {\n            label: 'common.button.cancel',\n            type: 'default',\n            onClick: () => {\n              modal.close();\n            }\n          },\n          {\n            label: 'common.button.confirm',\n            type: 'primary',\n            onClick(formCpn: DppFormComponent) {\n              const isValid = formCpn.onSubmit();\n              const formData = formCpn.getFormData() as IBaseData;\n\n              if (isValid) {\n                this.loading = true;\n                const params = {\n                  LIBRARYGUID: formData['GUID$'],\n                  TEMPLATENAME: formData['FOLDERNAME'],\n                  DESCRIPTION: formData['DESCRIPTION']\n                };\n                that.productDesignService\n                  .saveLibraryTemplate(params)\n                  .pipe(\n                    finalize(() => {\n                      this.loading = false;\n                    })\n                  )\n                  .subscribe({\n                    next: res => {\n                      formCpn.setLoading(false);\n                      if (res.data && res.success) {\n                        that.dppMessageService.success('common.operation.operationSuccess');\n                        table.refreshData();\n                        modal.close();\n                      }\n                    },\n                    error: _err => {\n                      formCpn.setLoading(false);\n                    }\n                  });\n              }\n            }\n          }\n        ]\n      },\n      {\n        dppRender: formParams\n      }\n    );\n  }"
