            "code": "  /**\n   * （料+CAD）创建事件\n   * @param event\n   */\n  sysNewObjectAndCADAction(event: EventInterface): void {\n    const exeModel = this.getExeModel(event);\n    const rootPage = this.getRootPageService(event);\n    const menuCom = CommonEventUtil.getDesignLibraryMenuCom(rootPage) as DppMenuComponent;\n    const tableCom = this.getContentCom<DppTableComponent>(event);\n    const action = exeModel?.['action'];\n    const choiceMenuObj = menuCom?.getSelectedData()?.data;\n    // const urlObj = parseUrl(menuCom?.dppRender?.mParams?.dataSource!, menuCom?.dppRender?.dParams);\n    const bs = this.getExeCom(event) as DppButtonComponent;\n    // let url = `${urlObj.url}?`;\n\n    // Object.keys(urlObj.params).forEach(key => {\n    //   url = url.endsWith('?') ? `${url}${key}=${urlObj.params[key]}` : `${url}&${key}=${urlObj.params[key]}`;\n    // });\n    this.setLoading(event, true);\n    this.boas.getCadConfig().subscribe({\n      next: res => {\n        if (res.success && res.data) {\n          let cadConfig = res.data;\n          const enabled = cadConfig.ENABLED === 'Y';\n\n          const render: WizardRender = {\n            name: action.name,\n            mParams: {\n              // initValue: `withMainFile=Y`,\n              isObject: action.isObject,\n              footerbar: action.footerbar\n            },\n            dParams: { ...cadConfig },\n            data: {\n              // folderDataSoure: url,\n              // libraryType: action['libraryType'],\n              ENABLED: enabled\n            }\n          };\n          generateFieldMapping({\n            mappingType: 'folder',\n            fieldKey: 'COMMITFOLDER$',\n            sourceData: choiceMenuObj['origin'],\n            onValueUpdate: (key, value) => {\n              render.data![key] = value;\n            },\n            isMapToObject: false\n          });\n          const modal: DppNzModalRef = this.as.openModal(\n            {\n              title: bs.getUiModel().label,\n              width: action.width,\n              bodyStyle: { height: action.height! },\n              closable: true,\n              // bodyStyle: { height: '40vh' },\n              // content: DppWizardComponent,\n              uiType: UIModelTypeEnum.WIZARD,\n              footer: 'noFooter',\n              isInteractive: false,\n              modalSelf: () => modal,\n              triggerInstance: () => tableCom\n            },\n            { dppRender: render }\n          );\n        }\n        this.setLoading(event, false);\n      },\n      error: err => this.setLoading(event, false)\n    });\n  }"
