            "code": "  /**\n   * 添加特定页签事件\n   * @param event\n   */\n  sysNewItemCADTDAddAction(event: EventInterface): void {\n    const wizardCom = this.getContentCom<DppWizardComponent>(event);\n    // const componentRefs = wizardCom.getComponentRefs();\n    // console.log(wizardCom.getWizardData());\n    const button = this.getExeCom<DppButtonComponent>(event);\n    const action = button.getUiModel().action!;\n    const formCom = wizardCom.getWizardHeadInstance<DppFormComponent>(0);\n    const formComData = formCom?.dppRender?.data;\n    let readyData = {\n      folderDataSoure: formComData?.['folderDataSoure'],\n      SYNFILENAME: wizardCom?.dppRender?.dParams?.['SYNFILENAME']\n    };\n    generateFieldMapping({\n      mappingType: 'folder',\n      fieldKey: 'COMMITFOLDER$',\n      sourceData: formComData,\n      onValueUpdate: (key, value) => {\n        readyData[key] = value;\n      }\n    });\n    const { data, expression } = this.cadConfigHandle({\n      configData: wizardCom?.dppRender?.dParams as CadConfig,\n      formCom,\n      data: readyData\n    });\n    const params: IFormRender = {\n      name: action.name,\n      mParams: {\n        mode: action.mode,\n        initValue: `withMainFile=Y`,\n        isObject: action.isObject,\n        expression\n      },\n      data\n    };\n\n    wizardCom.addStepPage('common.title.choiceCad', DppFormComponent, { dppRender: params });\n\n    wizardCom.getWizardHeadModels().forEach((uiModel, index) => {\n      uiModel.nzDisable = false;\n    });\n  }"
