            "note": "替代查看-局部替代-新增按钮 @param event",
            "code": "  /**\n   * 替代查看-局部替代-新增按钮\n   * @param event\n   */\n  sysBRSPartNewlyBuiltAction(event: EventInterface, params?: Record<string, DppSafeAny>): void {\n    const table = this.getContentCom(event) as unknown as DppTableComponent;\n    const btn = this.getExeCom<DppButtonComponent>(event);\n    const data = btn.dppRender?.config?.dParams;\n    const trigger = table.dppRender.innerSend?.triggerInstance?.() as DppTableComponent;\n    const rowNode = trigger.getDisplayedNodes().find(node => node.origin['GUID$'] === data?.bomGuid);\n\n    const onConfirm = (\n      selectedCpn: DppPageComponent,\n      modal: DppNzModalRef,\n      setLoading: (loading: boolean) => void\n    ): void => {\n      let selectedRows = this.substituteUtil.bRScollectSelectedData(selectedCpn);\n      if (selectedRows.length === 0) {\n        this.dppMessageService.warning('substitute.prompt.noDataSelected');\n        return;\n      }\n\n      // 过滤自身数据\n      const filteredRows = selectedRows.filter(item => item['GUID$'] !== data?.END2$GUID);\n\n      if (filteredRows.length === 0) {\n        this.dppMessageService.warning('substitute.prompt.hasOnlyFilterItself');\n        return;\n      }\n\n      if (filteredRows.length < selectedRows.length) {\n        this.dppMessageService.warning('substitute.prompt.hasFilterItself');\n        selectedRows = filteredRows;\n      }\n\n      setLoading(true);\n      const addParams = params || this.substituteUtil.bRSbuildNewParams(data, selectedRows);\n      this.substituteService.bRSbatchLinkSubItems(addParams).subscribe({\n        next: res => {\n          if (res.data && res.success) {\n            const { successCnt, totalCnt, errorCnt, details } = res.data;\n\n            if (successCnt && successCnt === totalCnt) {\n              this.dppMessageService.success('common.operation.operationSuccess');\n            } else {\n              this.errorMessageService.showMessage(event, res);\n            }\n\n            const successAdded = details\n              ?.filter((item: any) => item.result === 'SUCCESS')\n              .map((item: any) => item.data);\n            if (successAdded.length > 0) {\n              // table.applyTransaction({\n              //   add: successAdded\n              // });\n              table.refreshData();\n            }\n            // 如果全部错误，不刷新表格\n            const canReplace = rowNode && rowNode.origin['RSFLAG'] !== 'Y' && rowNode.origin['RSVIEW'] !== 'Y';\n            this.substituteUtil.updateBomNodeStatus(table, {\n              RSFLAG: 'Y',\n              RSINVALID: 'N',\n              judge: () => Boolean(errorCnt !== totalCnt && canReplace)\n            });\n\n            if (errorCnt !== totalCnt) {\n              modal.close();\n            }\n          }\n          setLoading(false);\n        },\n        error: err => {\n          setLoading(false);\n        }\n      });\n    };\n\n    const openParams = this.substituteUtil.bRSbuildOpenModalParams(event, false, data);\n\n    this.substituteUtil.bRSopenSubItemModal(event, onConfirm, openParams);\n  }"
