            "id": "pdm_c19_12",
            "name": "sysBRSWholeNewlyBuiltAction",
            "lines": 41,
            "event_type": "event: EventInterface",
            "note": "替代查看-全局替代-新增按钮 @param event",
            "code": "  /**\n   * 替代查看-全局替代-新增按钮\n   * @param event\n   */\n  sysBRSWholeNewlyBuiltAction(event: EventInterface): void {\n    const tableCom = this.getContentCom<DppTableComponent>(event);\n    const exeModel = this.getExeModel(event);\n    const action = exeModel?.['action'];\n    const btn = this.getExeCom<DppButtonComponent>(event);\n    const data = btn.dppRender?.config?.dParams;\n    const dppRenderData = this.substituteUtil.getBRSFetchAfterAddGlobalInitData(data);\n    const sendData = {\n      // COMMITFOLDER$: data?.['END2#COMMITFOLDER$'],\n      // COMMITFOLDER$NAME: data?.['END2#COMMITFOLDER$PATH'],\n      COMPONENT_ITEM: {\n        GUID: data?.['END2$GUID'],\n        CLASSNAME: data?.['END2$CLASSNAME']\n      },\n      CLASSNAME: data?.['END2#CLASSNAME'],\n      GUID: data?.['END2#GUID'],\n      ROWKEY: data?.['ROWKEY']\n    };\n    generateFieldMapping({\n      mappingType: 'folder',\n      fieldKey: 'END2#COMMITFOLDER$',\n      sourceData: data,\n      onValueUpdate: (key, value) => {\n        sendData[key] = value;\n        sendData[key?.split('#')[1]] = value;\n      }\n    });\n\n    const that = this;\n    this.setLoading(event, true);\n    this.fetchAndProcessOptions({\n      action,\n      data: sendData,\n      tableCom,\n      fromType: 'global',\n      expression: 'SCOPE:editable=false',\n      optionName: 'Global',\n      secondData: dppRenderData,\n      event\n    });\n  }"
