            "code": "    generateFieldMapping({\n      mappingType: 'folder',\n      fieldKey: 'END2#COMMITFOLDER$',\n      sourceData: data,\n      onValueUpdate: (key, value) => {\n        sendData[key] = value;\n        sendData[key?.split('#')[1]] = value;\n      }\n    });"
