            "code": "    generateFieldMapping({\n      mappingType: 'folder',\n      fieldKey: 'COMMITFOLDER$',\n      sourceData: { ...dParams, ...data, ...(config || {}) },\n      onValueUpdate: (key, value) => {\n        sendData[key] = value;\n      }\n    });"
