            "code": "  /**\n   * 替代查看-全局替代-批量修改\n   */\n  sysWholeBatchModifyAction(event: EventInterface, config?: WholeModifyConfig): void {\n    const tableCom = this.getContentCom<DppTableComponent>(event);\n    const exeModel = this.getExeModel(event);\n    const action = exeModel?.['action'];\n    const btn = this.getExeCom<DppButtonComponent>(event);\n    const dParams = btn.dppRender?.config?.dParams;\n\n    const selectData = this.getSelectData(event);\n    const paramsData = {\n      ...dParams\n      // COMMITFOLDER$: dParams?.['END2#COMMITFOLDER$'],\n      // COMMITFOLDER$NAME: dParams?.['END2#COMMITFOLDER$NAME']\n    };\n\n    if (config) {\n      generateFieldMapping({\n        mappingType: 'folder',\n        fieldKey: 'COMMITFOLDER$',\n        sourceData: { ...dParams, ...(config || {}) },\n        onValueUpdate: (key, value) => {\n          paramsData[key] = value;\n        }\n      });\n    } else {\n      generateFieldMapping({\n        mappingType: 'folder',\n        fieldKey: 'END2#COMMITFOLDER$',\n        sourceData: { ...dParams },\n        onValueUpdate: (key, value) => {\n          paramsData[key] = value;\n          paramsData[key?.split('#')[1]] = value;\n        }\n      });\n    }\n    this.setLoading(event, true);\n    this.fetchAndProcessOptions({\n      action,\n      tableCom,\n      data: paramsData,\n      fromType: 'global',\n      expression: 'SCOPE:editable=false',\n      rowDatas: selectData.map(item => ({\n        GUID: item['GUID$'],\n        CLASSNAME: item['CLASSNAME$'],\n        FULL_NAME: item['FULLNAME$'],\n        ID: item['ID$']\n      })),\n      optionName: 'Global',\n      event\n    });\n  }"
