            "code": "  /**\n   * 替代申请弹窗-完成按钮\n   * @param event\n   */\n  sysBRSApplyForCompleteAction(event: EventInterface): void {\n    const wizardCom = this.getContentCom<DppWizardComponent>(event);\n    let fromType = wizardCom.dppRender.dParams?.['fromType'];\n    let dppRenderData = wizardCom.dppRender.data;\n    // 如果用户自己选择的处理\n    const formCom = wizardCom.getWizardHeadInstance<DppFormComponent>(0);\n    const formData = formCom.getFormData() || {};\n    const scope = formData['SCOPE$CODE'];\n\n    scope === 'Global' ? (fromType = 'global') : (fromType = 'part');\n    const saveObject$ = this.sysBRSCompleteAction(event, {\n      openObject: false,\n      refreshTable: false,\n      isRepeat: false,\n      fromType,\n      dppRenderData: dppRenderData as Record<string, any>\n    });\n\n    // 根据 fromType 处理不同的逻辑\n    if (fromType === 'part') {\n      this.handlePartType(event, saveObject$, wizardCom);\n    } else if (fromType === 'global') {\n      this.handleGlobalModifyType(event, saveObject$ as Observable<IBatchData>, wizardCom);\n    } else {\n      this.handleDefaultType(saveObject$);\n    }\n  }"
