            "code": "  /**\n   * 主件加载完后联动替代件\n   * @param event\n   */\n  sysBRSDRMQueryAfterAction(event: EventInterface): void {\n    const { exeTable, contentTable, instanceData } = this.substituteUtil.getBRSDRMCommonComponentsAndData(event);\n    const mainTable = exeTable;\n    const subTable = contentTable;\n    if (!mainTable || !subTable || !instanceData) return;\n\n    const selectNode = mainTable.getAllNodes()[0];\n    if (!selectNode) {\n      console.warn('No nodes found in the main table.');\n      return;\n    }\n\n    mainTable.setNodeSelected(0);\n    const params = this.substituteUtil.getBRSDRRefreshParams(selectNode, instanceData);\n    subTable.refreshByParams(params);\n\n    // subTable.afterQueryData.subscribe({\n    //   next: res => {\n    //     const subNodes = subTable.getAllNodes();\n    //     subNodes.forEach(node => {\n    //       node.origin['preType'] = 'modify';\n    //     });\n\n    //     subTable.applyTransaction({\n    //       update: subNodes\n    //     });\n    //   },\n    //   error: err => {\n    //     console.error('Error in afterQueryData subscription:', err);\n    //   }\n    // });\n  }"
