            "note": "主件-opt-移除按钮 @param event",
            "code": "  /**\n   * 主件-opt-移除按钮\n   * @param event\n   */\n  sysBRSAFDMRemoveCheckAction(\n    event: EventInterface,\n    data?: IBaseData,\n    callBack?: (res: DppResponse<IBatchData<IBatchDataDetails>>) => void\n  ): void {\n    const rootPage = this.getRootPageService(event);\n    const instanceData = rootPage.getInstanceData();\n    const node = this.getNode(event) as RowNode;\n    const params = this.substituteUtil.getbRSSubMainRelationDelParam(data || instanceData, node);\n    const table = this.getContentCom<DppTableComponent>(event);\n    this.setLoading(event, true);\n    this.substituteService.bRSSubMainRelationDel(params).subscribe({\n      next: res => {\n        if (res.success) {\n          this.dppMessageService.success('common.operation.operationSuccess');\n          table!.refreshData().subscribe({\n            next: () => {\n              this.substituteUtil.mainRemoveDelUpdateData(rootPage, table, instanceData);\n              if (callBack && typeof callBack === 'function') {\n                callBack.call(this, res);\n              }\n            }\n          });\n        }\n        this.setLoading(event, false);\n      },\n      error: () => {\n        this.setLoading(event, false);\n      }\n    });\n  }",
            "toRemove": true
