            "code": "  /**\n   * 导出编辑表\n   * @param event\n   */\n  sysBRSDetailRightTopExportTableAction(event: EventInterface): void {\n    const rootPage = this.getRootPageService(event);\n    const instanceData = rootPage.getInstanceData();\n\n    const scope = instanceData['SCOPE$CODE'];\n    let commandStr = 'sysBRSDetailRightReplaceCommand';\n    // 从主件\n    if (scope === 'Partial2') {\n      commandStr = 'sysBRSDetailRightComReplaceCommand';\n    }\n    if (scope === 'Global') {\n      commandStr = 'sysBRSDetailRightGlobalReplaceCommand';\n    }\n    let params = this.substituteUtil.getExportTableParams(instanceData);\n    this.setLoading(event, true);\n    this.substituteService.downloadSubImportTemplate(params).subscribe({\n      next: res => {\n        this.substituteUtil.downloadBlob(res.data!, `${instanceData['ID$']}.xlsx`);\n        if (res.success) {\n          this.dppMessageService.success('substitute.message.exportSuccess');\n        }\n        this.setLoading(event, false);\n      },\n      error: err => {\n        this.setLoading(event, false);\n      }\n    });\n  }"
