            "code": "  // 替代方案新增\n  sysReplaceSchemeAddAction(event: EventInterface): void {\n    // eslint-disable-next-line @typescript-eslint/no-this-alias\n    const _this = this;\n    const bs = this.getExeCom(event) as DppButtonComponent;\n    const action = bs.getUiModel().action as ButtonIUiModel;\n    const table = this.getContentCom(event) as DppTableComponent;\n    const page = this.getRootPageService(event);\n    const InstanceData = page.getInstanceData() as IFoundaton;\n\n    const formParams: IFormRender = {\n      name: FormConfigModelEnum.REPLACESCHEMEADD,\n      mParams: {\n        mode: ModeTypeEnum.EDIT,\n        isObject: false,\n        model: {}\n      }\n    };\n\n    const modal = this.as.openModal(\n      {\n        title: 'substitute.command.sysAddReplaceSolutionCommand',\n        width: '600px',\n        // height: '230px',\n        closable: true,\n        content: DppFormComponent,\n        footer: [\n          {\n            label: 'common.button.cancel',\n            type: 'default',\n            onClick: () => {\n              modal.close();\n            }\n          },\n          {\n            label: 'common.button.confirm',\n            type: 'primary',\n            onClick(formCpn: DppFormComponent) {\n              const isValid = formCpn.onSubmit();\n              const formDatas = formCpn.getFormData() as DppSafeAny;\n              // debugger\n\n              if (isValid) {\n                formCpn.setLoading(true);\n                this.loading = true;\n                const params = {\n                  GUID$: formDatas['GUID$'] ?? '',\n                  CLASSNAME$: formDatas['CLASSNAME$'],\n                  MASTERFK$: formDatas['MASTERFK$'] ?? '',\n                  ISAUTOCHECKOUT$: formDatas['ISAUTOCHECKOUT$'],\n                  props: {\n                    ID$: formDatas['ID$'] ?? '',\n                    NAME$: formDatas['NAME$'],\n                    FORMTYPE: formDatas['FORMTYPE'],\n                    RSSTRATEGY: formDatas['RSSTRATEGY']\n                  }\n                };\n                _this.substituteService.createSolution(params).subscribe({\n                  next: res => {\n                    if (res.success && res.data) {\n                      formCpn.setLoading(false);\n                      this.loading = false;\n                      modal?.close();\n                      _this.dppMessageService.success('common.operation.newSuccess');\n\n                      // 打开新页签\n                      const property = {\n                        uiType: 'instance',\n                        routePath: '/instance'\n                      };\n                      const params = {\n                        dppRender: {\n                          className: res.data['CLASSNAME$'],\n                          guid: res.data['GUID$']\n                        }\n                      };\n                      _this.as.openBlank(property, params);\n\n                      // 关联\n                      const linkMainItems = {\n                        end1: {\n                          className: res.data['CLASSNAME$'],\n                          guid: res.data['GUID$']\n                        },\n                        structures: [\n                          {\n                            end2: {\n                              className: InstanceData['CLASSNAME$'],\n                              guid: InstanceData['GUID$'],\n                              classGuid: InstanceData['CLASSGUID$']\n                            },\n                            props: {},\n                            modifyType: 'ADD'\n                          }\n                        ]\n                      };\n                      _this.substituteService.batchLinkMainItems(linkMainItems).subscribe({\n                        next: res => {\n                          table.refreshData();\n                        }\n                      });\n                    }\n                  },\n                  error: err => {\n                    // modal?.close();\n                    formCpn.setLoading(false);\n                    this.loading = false;\n                  }\n                });\n              }\n            }\n          }\n        ]\n      },\n      {\n        dppRender: formParams\n      }\n    );\n  }"
