            "code": "  // 新增主物料\n  sysMainItemAddAction(event: EventInterface): void {\n    const bs = this.getExeCom(event) as DppButtonComponent;\n    const action = bs.getUiModel().action as IUIAction;\n    const page = this.getRootPageService(event);\n    const RSSolutionData = page.getInstanceData() as IFoundaton;\n\n    const params = {\n      name: action['name'],\n      mParams: {\n        ...action,\n        dataSource: `${action['dataSource']}?guid=${RSSolutionData['GUID$']}&className=${RSSolutionData['CLASSNAME$']}&classGuid=${RSSolutionData['CLASSGUID$']}&ISFROMMASTERITEM=Y`\n      },\n      dParams: {\n        RSSolutionData\n      }\n    };\n\n    const modal = this.as.openModal(\n      {\n        title: 'substitute.command.sysAddMainItemCommand',\n        closable: true,\n        // full: action['full'],\n        width: '80vw',\n        height: '66vh',\n        bodyStyle: {\n          maxHeight: '680px',\n          borderRadius: '5px',\n          overflowY: 'auto',\n          padding: '10px'\n        },\n        content: DppTableComponent,\n        modalSelf: () => modal,\n        triggerInstance: () => this.getContentCom(event),\n        reFreshCallBack: () => {\n          modal?.close();\n        },\n        footer: [\n          {\n            label: 'common.button.cancel',\n            type: 'default',\n            onClick: () => {\n              modal.close();\n            }\n          }\n        ]\n      },\n      {\n        dppRender: params\n      }\n    ) as DppNzModalRef;\n  }"
