            "note": "参考主物料",
            "code": "  // 参考主物料\n  sysReferenceMainItemAction(event: EventInterface): void {\n    const bs = this.getExeCom(event) as DppButtonComponent;\n    const action = bs.getUiModel().action as IUIAction;\n    const rowData = this.getRowData(event) as ReferenceMainItems;\n    const table = this.getContentCom(event) as DppTableComponent;\n    const allData = table.getTreeNodes();\n\n    const trigger = table.dppRender.innerSend;\n    const instanceData = table.dppRender.dParams!['RSSolutionData'];\n\n    const params = {\n      name: action['name'],\n      mParams: {\n        ...action,\n        dataSource: `${action['dataSource']}?guid=${instanceData['GUID$']}&className=${instanceData['CLASSNAME$']}&classGuid=${instanceData['CLASSGUID$']}&viewClassGuid=${rowData['STRUCTURE#VIEWCLASSGUID$']}&viewGuid=${rowData['STRUCTURE#VIEWFK$']}`\n      },\n      dParams: {\n        // guid: instanceData['GUID$'],\n        // className: instanceData['CLASSNAME$'],\n        // classGuid: instanceData['CLASSGUID$'],\n        // viewClassGuid: rowData['STRUCTURE#VIEWCLASSGUID$']\n      }\n    };\n\n    const modal = this.as.openModal(\n      {\n        title: 'substitute.command.sysReferenceMainItemCommand',\n        closable: true,\n        // full: action['full'],\n        width: '80vw',\n        height: '66vh',\n        bodyStyle: {\n          maxHeight: '680px',\n          borderRadius: '5px',\n          overflowY: 'auto',\n          padding: '10px'\n        },\n        content: DppTableComponent,\n        footer: [\n          {\n            label: 'common.button.cancel',\n            type: 'default',\n            onClick: () => {\n              modal.close();\n            }\n          },\n          {\n            label: 'common.button.confirm',\n            type: 'primary',\n            onClick: (tableCpn: DppTableComponent) => {\n              modal.close();\n              trigger?.['modalSelf']?.().close(); // 关闭上一个弹窗\n\n              const selectedDatas = tableCpn.getCheckedNodeList();\n              const structuresParams: Array<{ [key: string]: object | string }> = [];\n\n              if (selectedDatas && selectedDatas.length > 0) {\n                selectedDatas.forEach(item => {\n                  // 关联\n                  structuresParams.push({\n                    end2: {\n                      className: item.origin['CLASSNAME$'],\n                      guid: item.origin['GUID$'],\n                      classGuid: item.origin['CLASSGUID$']\n                    },\n                    props: {},\n                    modifyType: 'ADD'\n                  });\n                });\n\n                let linkMainItems = {\n                  end1: {\n                    className: instanceData['CLASSNAME$'],\n                    guid: instanceData['GUID$']\n                  },\n                  structures: structuresParams\n                };\n                const viewGuids: string[] = [rowData['STRUCTURE#VIEWFK$']!];\n\n                this.substituteService.batchLinkMainItems(linkMainItems, viewGuids).subscribe({\n                  next: res => {\n                    if (res.data && res.success) {\n                      this.dppMessageService.success('substitute.prompt.newMainItemSuccess');\n                      trigger?.['triggerInstance']?.().refreshData();\n                    }\n                  }\n                });\n              } else {\n                this.dppMessageService.success('substitute.prompt.noDataSelected');\n              }\n            }\n          }\n        ]\n      },\n      {\n        dppRender: params\n      }\n    );\n  }"
