            "note": "新增替代物料组 @author: lsp @modify: 陈龙 2025-01-02 修改添加后的表格刷新，优化添加逻辑",
            "code": "  /**\n   * 新增替代物料组\n   * @author: lsp\n   * @modify: 陈龙 2025-01-02 修改添加后的表格刷新，优化添加逻辑\n   */\n  sysNewReplaceItemGroupAction(event: EventInterface): void {\n    const table = this.getContentCom(event) as unknown as DppTableComponent;\n    // eslint-disable-next-line @typescript-eslint/no-explicit-any\n    const instanceData = (this.getRootPageService(event) as any)['instanceData'];\n\n    const onConfirm = (\n      selectedCpn: DppPageComponent,\n      modal: DppNzModalRef,\n      setLoading: (loading: boolean) => void\n    ): void => {\n      setLoading(true);\n      const selectedRows = this.collectSelectedData(selectedCpn);\n      if (selectedRows.length === 0) {\n        this.dppMessageService.warning('substitute.prompt.noDataSelected');\n        return;\n      }\n      const addParams = this.buildNewParams(instanceData, selectedRows, table);\n      this.substituteService.batchLinkSubItems(addParams).subscribe({\n        next: res => {\n          if (res.data && res.success) {\n            const { successCnt, totalCnt, errorCnt, details } = res.data;\n            if (successCnt && successCnt === totalCnt) {\n              this.dppMessageService.success('substitute.prompt.newSubItemGroupSuccess');\n            } else {\n              this.errorMessageService.showMessage(event, res);\n            }\n\n            const successAdded = details.filter((item: any) => item.result === 'SUCCESS').map((item: any) => item.data);\n            if (successAdded.length > 0) {\n              table.applyTransaction({\n                add: successAdded\n              });\n            }\n            setLoading(false);\n            // 全部失败， 不需要刷新表格\n            if (totalCnt === errorCnt) return;\n            modal.close();\n          }\n        },\n        error: err => {\n          setLoading(false);\n        }\n      });\n    };\n\n    const openParams = this.buildOpenModalParams(event, false);\n\n    this.openSubItemModal(event, onConfirm, openParams);\n  }"
