            "code": "  /**\n   * 新增替代物料组｜行操作上的添加 --> 打开高级搜索\n   * @author: lsp\n   * @modify: 陈龙 2025-01-02 修改添加后的表格刷新，优化添加逻辑\n   */\n  sysOpenGlobalSearchAction(event: EventInterface): void {\n    this.setLoading(event, true);\n    const buttonModel: IButtonUiModel = this.getExeModel(event) as IButtonUiModel;\n    const table = this.getContentCom<IBaseContentComponent>(event) as unknown as DppTableComponent;\n    const trigger = table.dppRender.innerSend! as any;\n    const page = trigger['getPageThis']()!;\n    const targetNode = page.dppRender.innerSend.getTargetNode();\n    const instanceData = page.dppRender.innerSend.getInstanceData();\n    const needRefreshTable = page.dppRender.innerSend.getTable();\n    // 是否是新增\n    const isAdd = targetNode !== null;\n\n    const onConfirm = (\n      globalSearch: DppGlobalSearchComponent,\n      modal: DppNzModalRef,\n      setLoading: (loading: boolean) => void\n    ): void => {\n      setLoading(true);\n      const selectedRows = globalSearch.table.getCheckedNodes().map(item => item.origin);\n      if (selectedRows.length === 0) {\n        this.dppMessageService.warning('substitute.prompt.noDataSelected');\n        return;\n      }\n\n      let params = isAdd\n        ? this.buildAddParams(instanceData, selectedRows, targetNode)\n        : this.buildNewParams(instanceData, selectedRows, needRefreshTable);\n\n      const save$ = isAdd\n        ? this.substituteService.batchEditSubItems(params)\n        : this.substituteService.batchLinkSubItems(params);\n      save$.subscribe({\n        next: res => {\n          if (res.data && res.success) {\n            const { successCnt, totalCnt, errorCnt, details } = res.data;\n            if (totalCnt !== successCnt) {\n              this.errorMessageService.showMessage(event, res);\n            } else {\n              this.dppMessageService.success('substitute.prompt.newSubItemGroupSuccess');\n            }\n            const successAddedData = details\n              .filter((item: any) => item.result === 'SUCCESS')\n              .map((item: any) => item.data);\n            if (successAddedData.length > 0) {\n              needRefreshTable.applyTransaction({\n                add: successAddedData\n              });\n            }\n            setLoading(false);\n            // 如果全部失败，则不关闭弹窗\n            if (totalCnt === errorCnt) return;\n            // 关闭上一个弹窗\n            trigger?.['modalSelf']?.().close();\n            modal.close();\n          }\n        },\n        error: err => {\n          setLoading(false);\n        }\n      });\n    };\n\n    const modal = this.as.openModal(\n      {\n        content: comNewObj.data['search'],\n        title: buttonModel.label,\n        full: true,\n        footer: [\n          {\n            label: 'common.button.cancel',\n            type: 'default',\n            onClick: () => {\n              modal.close();\n            }\n          },\n          {\n            label: 'common.button.confirm',\n            type: 'primary',\n            onClick(globalSearch: DppGlobalSearchComponent) {\n              const setLoading = (loading: boolean): void => {\n                this.loading = loading;\n              };\n\n              onConfirm(globalSearch, modal, setLoading);\n            }\n          }\n        ]\n      },\n      {\n        dppRender: buttonModel.action\n      }\n    ) as DppNzModalRef;\n    modal.afterClose.subscribe(() => {\n      this.setLoading(event, false);\n    });\n  }"
