            "note": "替代查看",
            "code": "  // 替代查看\n  sysReplaceViewAction(event: EventInterface): void {\n    this.setLoading(event, true);\n    const rowData = this.getRowData(event) as ReplaceSetItems;\n    const params = {\n      className: rowData['END2#CLASSNAME$']!,\n      guid: rowData['END2#GUID$']!,\n      bomfk: rowData['GUID$']! // 主键\n    };\n\n    this.substituteService.listSolutionForBOM(params).subscribe({\n      next: res => {\n        if (res.data.length > 0 && res.success) {\n          const property = {\n            uiType: 'instance',\n            routePath: '/instance'\n          };\n          const newParams = {\n            dppRender: {\n              className: res.data[0]['CLASSNAME$'],\n              guid: res.data[0]['GUID$']\n            }\n          };\n          this.as.openBlank(property, newParams);\n        } else {\n          this.dppMessageService.error('substitute.prompt.noRelatedRSolution');\n        }\n        this.setLoading(event, false);\n      },\n      error: err => {\n        this.setLoading(event, false);\n      }\n    });\n  }"
