            "event_type": "selectedDatas: RowNode[]",
            "note": "获取",
            "code": "  // 获取\n  private getNodesInSelectedGroups(selectedDatas: RowNode[]): RowNode[] {\n    // 优先级相同的只需要留一个\n    let levelMap = new Map<number, RowNode>();\n    selectedDatas.forEach(item => {\n      if (!levelMap.has(item.origin['PRIORITY'])) {\n        levelMap.set(item.origin['PRIORITY'], item);\n      }\n    });\n\n    const result: RowNode[] = [];\n    levelMap.forEach(item => {\n      // 同组的都加上去\n      const sameGroup = item.parentNode!.childrenAfterSort;\n      result.push(...sameGroup);\n    });\n\n    return result;\n  }"
