            "event_type": "event: EventInterface",
            "note": "替代物料表格添加",
            "code": "  // 替代物料表格添加\n  sysReplaceItemOptionAddAction(event: EventInterface): void {\n    const targetNode = this.getNode(event) as RowNode;\n    const table = this.getContentCom(event) as unknown as DppTableComponent;\n    const page = this.getRootPageService(event);\n    const instanceData = page.getInstanceData() as IFoundaton;\n\n    const onConfirm = (\n      modalPage: DppPageComponent,\n      modal: DppNzModalRef,\n      setBtnLoading: (loading: boolean) => void\n    ): void => {\n      setBtnLoading(true);\n      const selectedRows = this.collectSelectedData(modalPage);\n      if (selectedRows.length === 0) {\n        this.dppMessageService.warning('substitute.prompt.noDataSelected');\n        setBtnLoading(false);\n        return;\n      }\n      const addParams = this.buildAddParams(instanceData, selectedRows, targetNode);\n\n      this.substituteService.batchEditSubItems(addParams).subscribe({\n        next: res => {\n          if (res.data && res.success) {\n            const { successCnt, totalCnt, errorCnt, details } = res.data;\n            if (totalCnt !== successCnt) {\n              this.errorMessageService.showMessage(event, res);\n            } else {\n              this.dppMessageService.success('substitute.prompt.newSubItemGroupSuccess');\n            }\n            const successAddedData = details\n              .filter((item: any) => item.result === 'SUCCESS')\n              .map((item: any) => item.data);\n            if (successAddedData.length > 0) {\n              table.applyTransaction({\n                add: successAddedData\n              });\n            }\n            setBtnLoading(false);\n            // 如果全部失败，则不关闭弹窗\n            if (totalCnt === errorCnt) return;\n            modal.close();\n          }\n        }\n      });\n    };\n    const modalParams = this.buildOpenModalParams(event, true);\n    this.openSubItemModal(event, onConfirm, modalParams);\n  }"
