            "code": "  // 获取新增操作的相关参数\n  private getCreateContext(event: EventInterface): { fromProcess: boolean; createTask: boolean } {\n    const table = this.getContentCom(event) as DppTableComponent;\n    const dParams = table.dppRender.dParams || {};\n    const fromProcess = dParams['fromProcess'] === 'true';\n\n    // 统一改为不创建任务\n    const createTask = false;\n    return { fromProcess, createTask };\n  }",
