            "event_type": "node: RowNode, permissionKey: keyof NodePermissions",
            "code": "  private hasNoPermission(node: RowNode, permissionKey: keyof NodePermissions): boolean {\n    const permissions = this.getNodePermissions(node);\n    return permissions?.[permissionKey] === 'N';\n  }"
