            "code": "  // 设计变更（保存）\n  // sysECMSaveAction(event: EventInterface): void {}\n  // 设计变更（完成）\n  sysECMCompleteAction(event: EventInterface): void {\n    const wizardCom = this.getContentCom<DppWizardComponent>(event);\n    const button = this.getExeCom<DppButtonComponent>(event);\n    const action = button.getUiModel().action!;\n    const formCom = wizardCom.getWizardHeadInstance<DppFormComponent>(0);\n    const formData = formCom.getNotTranFormData<IBaseData>();\n\n    const params: RouteUrlKeyParams = {\n      model: button.getUiModel().action,\n      data: formData,\n    }\n    const routeUi = this.routeService.getRouteUIByKey(button.getUiModel().action['route'])!\n    const tranParams = DppTargetRouteUtil.parseUrlKey(params);\n    const routePath = DppTargetRouteUtil.getRouteQueryString({ routeUi, tranParams })\n    const property = {\n      title: routePath,\n      routePath\n    };\n\n    this.as.openBlank(property);\n\n    CommonEventUtil.getModal(event)?.close();\n  }"
