            "code": "  /**\n   * @description 通知消息全选|取消全选\n   * @use 通知\n   * @param event\n   */\n  sysCancelAction(event: EventInterface): void {\n    const table = this.getContentCom(event) as unknown as DppTableComponent;\n    const name = this.getExeModel(event).name;\n    const status = name !== 'sysCancelCommand';\n    table.setAllChecked(status);\n  }"
