            "note": "提交 @use 流程-上方toolbar @param event",
            "code": "  /**\n   * 提交\n   * @use 流程-上方toolbar\n   * @param event\n   */\n  sysApproveSubmitAction(event: EventInterface): void {\n    this.setLoading(event, true);\n    const page = this.getRootPageService(event);\n    const table = page.getComFnMapByName<DppTableComponent>('sysApproveObjectTableCommand');\n    const dppRender = this.getContentCom<IBaseContentComponent>(event)['dppRender'];\n    const procRtGuid = dppRender.dParams?.['guid'] as string;\n    this.workFlowService\n      .checkAttachmentsAndPerformer(procRtGuid)\n      .pipe(\n        switchMap(res => {\n          if (res.success) {\n            return this.workFlowService.verifyValidAttach(procRtGuid);\n          } else {\n            return of(null);\n          }\n        }),\n        catchError(err => {\n          this.setLoading(event, false);\n          throw of(null);\n        })\n      )\n      .subscribe(res => {\n        if (!res) {\n          this.setLoading(event, false);\n          return;\n        }\n        if (res.data && (res.data as object[]).length) {\n          const modal: DppNzModalRef = this.as.openModal(\n            {\n              content: DppTableComponent,\n              width: '800px',\n              height: '500px',\n              footer: [\n                {\n                  label: 'common.button.cancel',\n                  type: 'default',\n                  onClick: () => {\n                    modal.close();\n                  }\n                },\n                {\n                  label: 'common.button.confirm',\n                  type: 'primary',\n                  onClick: () => {\n                    modal.close();\n                    this.sysApproveSubmitValidAction(event);\n                  }\n                }\n              ]\n            },\n            {\n              dppRender: {\n                name: 'sysApproveErrorTable',\n                data: res.data,\n                toolbar: 'sysApproveErrorToolbar'\n              }\n            }\n          );\n          modal.afterClose.subscribe(() => {\n            this.setLoading(event, false);\n          });\n        } else {\n          this.sysApproveSubmitValidAction(event);\n        }\n      });\n  }"
