            "code": "  /**\n   * 删除\n   * @use 流程-上方toolbar\n   * @param event\n   */\n  sysApproveDeleteAction(event: EventInterface): void {\n    // 这个可以拿到触发组件的实例！！！也就是说删除的时候调用这个实例的表格callback方法就行！！！\n    const content = this.getContentCom<DppFormComponent>(event);\n    let innerSend = content?.dppRender?.innerSend;\n    const page = this.getRootPageService(event);\n    const triggerInstance = innerSend?.triggerInstance;\n\n    let deleteTitle = 'common.confirmDelete.deleteTitle';\n    let deleteContent = 'common.confirmDelete.deleteContent';\n    this.dppTranslateService.get(deleteTitle).subscribe(res => {\n      deleteTitle = res;\n    });\n    this.dppTranslateService.get(deleteContent).subscribe(res => {\n      deleteContent = res;\n    });\n    const OkText = this.translate.transform('basic.system.boolean.Y');\n    const cancelText = this.translate.transform('basic.system.boolean.N');\n    const modal = this.getTriggerModal(event) as DppNzModalRef;\n    this.modal.confirm({\n      nzTitle: deleteTitle,\n      nzContent: deleteContent,\n      nzOkText: OkText,\n      nzOkType: 'primary',\n      // nzOkDanger: true,\n      nzOnOk: () => {\n        const guid = content?.dppRender.dParams?.['guid'] as string;\n        page.setLoading('sysApprovePage', true);\n        this.workFlowService.deleteWorkflow(guid).subscribe(res => {\n          page.setLoading('sysApprovePage', false);\n          this.dppMessageService.success('workflow.operation.deleteWfSuccess');\n          if (modal) {\n            if (triggerInstance && typeof triggerInstance === 'function') {\n              this.contentComCallback(\n                event,\n                {\n                  operate: EventCallbacksActionName.REFRESH\n                },\n                triggerInstance()\n              );\n            }\n            modal.close();\n          } else {\n            this.closeAction({ router: this.router, modal, closeNow: true });\n          }\n        });\n      },\n      nzCancelText: cancelText,\n      nzOnCancel: () => console.log('Cancel')\n    });\n  }"
