            "code": "  // 图纸审批里 下载所有图纸  可视化审批\n  sysDrawApproveDownLoadAllAction(event: EventInterface): void {\n    const rootPage = this.getRootPageService(event);\n    const fileBottomPage = rootPage.getChildPage<DppPageComponent>('sysDrawApproveBottomPageCommand');\n    const tableContent = fileBottomPage.getPageThis().getChildPage<DppTableComponent>('sysDrawApproveTableCommand');\n    const params = {\n      procRtGuid: tableContent.dppRender?.dParams!['GUID'] || tableContent.dppRender?.dParams!['GUID$'],\n      extension: 'pdf'\n    };\n    const setBtnLoading = (loading: boolean): void => {\n      this.setLoading(event, loading);\n    };\n    this.downloadAllDrawing(params, setBtnLoading);\n  }"
