            "note": "保存批注",
            "code": "  // 保存批注\n  sysSaveIntevueCommentCommonAction(event: EventInterface, targetNode?: RowNode, isShowMsg?: boolean): void {\n    this.drawApproveHasInit = true;\n    const interVueCom = this.getRootPageService(event);\n    const previewIframe = interVueCom.getComFnMapByName(\n      'sysDrawApproveFilePreviewCommand'\n    ) as unknown as ViewerComponent;\n    const previewTable = interVueCom.getComFnMapByName('sysDrawApproveTableCommand') as unknown as DppTableComponent;\n    const data = previewTable?.getTreeNodes();\n    const rowData = previewTable.getSelectedNodeList()?.[0] ? previewTable.getSelectedNodeList()?.[0] : data[0];\n    const actRtGuid = previewIframe.dppRender.dParams?.['actRtGuid'];\n    // const rowInx = data.findIndex(item => item.key === rowData.key);\n    if (!rowData) {\n      this.dppMessageService.info('workflow.operation.NoReviewObject');\n      return;\n    }\n    const rowInx = targetNode?.rowIndex ?? (rowData.rowIndex as number);\n\n    const saveCommon = (param: IAnnotationComment, actRtGuid: string, isShowMsg?: boolean): void => {\n      this.workFlowService.saveAnnotationComment(param, actRtGuid).subscribe({\n        next: res => {\n          if (res.success && res.data) {\n            if (isShowMsg) {\n              this.dppMessageService.success('common.operation.operationSuccess');\n            }\n            previewTable?.refreshData().subscribe(res => {\n              previewTable.setNodeSelected(rowInx);\n            });\n          }\n        }\n      });\n    };\n\n    if (previewIframe['fileType'] === 'ZI_QI_AN') {\n      const Data = JSON.stringify(previewIframe['ZI_QI_AN']?.['remarkData']);\n      const fileTags = previewIframe.dppRender.dParams?.['fileTags'] as IAnnotationComment;\n      const param = {\n        REVIEW_GUID: rowData?.origin!['REVIEW_GUID'][0],\n        ANNOTATION_COMMENT: fileTags?.ANNOTATION_COMMENT,\n        ANNOTATION_COMMENT$JSON: Data\n      };\n      saveCommon(param, actRtGuid);\n      return;\n    }\n\n    if (previewIframe['fileType'] === 'NEW_DI_3D' || previewIframe['fileType'] === 'NEW_DI_2D') {\n      const writeTags = (window as any).nd_viewCtrl.getTags();\n      const fileTags = previewIframe.dppRender.dParams?.['fileTags'] as IAnnotationComment;\n      const Data = JSON.stringify(writeTags);\n      const param = {\n        REVIEW_GUID: rowData?.origin!['REVIEW_GUID'][0],\n        ANNOTATION_COMMENT: fileTags?.ANNOTATION_COMMENT,\n        ANNOTATION_COMMENT$JSON: Data\n      };\n      saveCommon(param, actRtGuid);\n    } else if (previewIframe['fileType'] === 'KK_FILE') {\n      // 富文本组件\n      const formCom = previewIframe?.['kkfile']['form'];\n      const formData = formCom.getFormData<any>();\n\n      // 获取富文本组件实例\n      const formService = formCom.getService();\n      const richCom = formService.getFieldCpmByKey<FormEditorComponent>('ANNOTATION_COMMENT');\n\n      // 判断富文本组件内容是否为空\n      const isEmpty = richCom.richCom.getEditor().isEmpty();\n      const param = {\n        REVIEW_GUID: rowData?.origin!['REVIEW_GUID'][0],\n        ANNOTATION_COMMENT: formData['ANNOTATION_COMMENT'],\n        ANNOTATION_COMMENT$JSON: isEmpty ? '' : formData['ANNOTATION_COMMENT$JSON']\n      };\n\n      const isChanged = formCom.isChangedByData();\n      console.log('isChanged', isChanged);\n\n      if (rowData?.origin!['REVIEW_GUID'][0] && isChanged) {\n        saveCommon(param, actRtGuid, isShowMsg);\n      }\n    }\n  }"
